'use client';

import React, { useState, useEffect, useCallback } from 'react';
import { createClient } from '@/utils/supabase/client';
import {
    BarChart3, AlertTriangle, CheckCircle2, XCircle, Plus, Minus,
    RefreshCw, PackageOpen, Search, X, Loader2, Bell, TrendingDown,
    Save, History, Archive, RotateCcw, Edit
} from 'lucide-react';

interface Product {
    id: string;
    title: string;
    sku: string | null;
    stock_quantity: number;
    low_stock_threshold: number;
    price: number;
    image_urls: string[];
    is_active: boolean;
}

export default function InventoryPage() {
    const supabase = createClient();
    const [products, setProducts] = useState<Product[]>([]);
    const [shopId, setShopId] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [filter, setFilter] = useState<'all' | 'low' | 'out' | 'archived'>('all');

    const [pendingEdits, setPendingEdits] = useState<Record<string, { stock_quantity?: number, low_stock_threshold?: number }>>({});
    const [isSavingBulk, setIsSavingBulk] = useState(false);

    const [restockProduct, setRestockProduct] = useState<Product | null>(null);
    const [restockDelta, setRestockDelta] = useState<number>(10);
    const [restockNote, setRestockNote] = useState('');
    const [isRestocking, setIsRestocking] = useState(false);

    const [historyProduct, setHistoryProduct] = useState<Product | null>(null);
    const [historyEvents, setHistoryEvents] = useState<any[]>([]);
    const [loadingHistory, setLoadingHistory] = useState(false);

    const fetchProducts = useCallback(async () => {
        setLoading(true);
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) { setLoading(false); return; }
        const { data: shop } = await supabase.from('shops').select('id').eq('owner_id', user.id).maybeSingle();
        if (shop) {
            setShopId(shop.id);
            const { data } = await supabase
                .from('products')
                .select('id, title, sku, stock_quantity, low_stock_threshold, price, image_urls, is_active')
                .eq('shop_id', shop.id)
                .order('stock_quantity', { ascending: true });
            if (data) {
                setProducts(data);
                setPendingEdits({});
            }
        }
        setLoading(false);
    }, [supabase]);

    useEffect(() => { fetchProducts(); }, [fetchProducts]);

    const handleEditField = (productId: string, field: 'stock_quantity' | 'low_stock_threshold', value: string) => {
        const num = Math.max(0, parseInt(value) || 0);
        setPendingEdits(prev => ({
            ...prev,
            [productId]: {
                ...prev[productId],
                [field]: num
            }
        }));
    };

    const getDisplayValue = (product: Product, field: 'stock_quantity' | 'low_stock_threshold') => {
        return pendingEdits[product.id]?.[field] ?? (product[field] || 0);
    };

    const handleBulkSave = async () => {
        const pIds = Object.keys(pendingEdits);
        if (pIds.length === 0) return;
        setIsSavingBulk(true);

        const adjustments = [];
        const thresholdUpdates = [];

        for (const pId of pIds) {
            const product = products.find(p => p.id === pId);
            if (!product) continue;

            const edit = pendingEdits[pId];
            if (edit.stock_quantity !== undefined && edit.stock_quantity !== product.stock_quantity) {
                const delta = edit.stock_quantity - product.stock_quantity;
                adjustments.push({ productId: pId, delta, reason: 'BULK_EDIT' });
            }
            if (edit.low_stock_threshold !== undefined && edit.low_stock_threshold !== (product.low_stock_threshold || 5)) {
                thresholdUpdates.push({ id: pId, low_stock_threshold: edit.low_stock_threshold });
            }
        }

        if (adjustments.length > 0) {
            await fetch('/api/inventory/adjust', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ adjustments })
            });
        }

        if (thresholdUpdates.length > 0) {
            for (const t of thresholdUpdates) {
                await supabase.from('products').update({ low_stock_threshold: t.low_stock_threshold }).eq('id', t.id);
            }
        }

        await fetchProducts();
        setIsSavingBulk(false);
    };

    const handleQuickRestockSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!restockProduct || restockDelta <= 0) return;
        setIsRestocking(true);

        await fetch('/api/inventory/adjust', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                adjustments: [{
                    productId: restockProduct.id,
                    delta: restockDelta,
                    reason: restockNote || 'QUICK_RESTOCK'
                }]
            })
        });

        await fetchProducts();
        setRestockProduct(null);
        setRestockDelta(10);
        setRestockNote('');
        setIsRestocking(false);
    };

    const fetchHistoryEvents = async (product: Product) => {
        setHistoryProduct(product);
        setLoadingHistory(true);
        const { data } = await supabase
            .from('stock_movements')
            .select('*')
            .eq('product_id', product.id)
            .order('created_at', { ascending: false })
            .limit(50);
        setHistoryEvents(data || []);
        setLoadingHistory(false);
    };

    const toggleArchive = async (productId: string, currentActive: boolean) => {
        if (!confirm(`Are you sure you want to ${currentActive ? 'archive' : 'unarchive'} this product?`)) return;
        await fetch('/api/inventory/archive', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ productIds: [productId], isActive: !currentActive })
        });
        await fetchProducts();
    };

    const activeProducts = products.filter(p => p.is_active !== false);
    const outOfStock = activeProducts.filter(p => p.stock_quantity === 0);
    const lowStock = activeProducts.filter(p => p.stock_quantity > 0 && p.stock_quantity <= (p.low_stock_threshold || 5));
    const inStock = activeProducts.filter(p => p.stock_quantity > (p.low_stock_threshold || 5));
    const archivedProducts = products.filter(p => p.is_active === false);

    const filtered = products.filter(p => {
        const matchSearch = p.title.toLowerCase().includes(search.toLowerCase()) || (p.sku && p.sku.toLowerCase().includes(search.toLowerCase()));

        if (filter === 'archived') return matchSearch && p.is_active === false;
        if (p.is_active === false) return false; // Prevent archived in other views

        if (filter === 'out') return matchSearch && p.stock_quantity === 0;
        if (filter === 'low') return matchSearch && p.stock_quantity > 0 && p.stock_quantity <= (p.low_stock_threshold || 5);
        return matchSearch;
    });

    const hasPendingEdits = Object.keys(pendingEdits).length > 0;

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-8 min-h-[60vh]">
                <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin" />
            </div>
        );
    }

    return (
        <div className="p-6 lg:p-8 max-w-7xl mx-auto space-y-6">

            {/* Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900 tracking-tight flex items-center gap-2">
                        <BarChart3 className="w-6 h-6 text-blue-600" /> Inventory & Stock
                    </h1>
                    <p className="text-sm text-gray-400 mt-0.5">Manage stock levels safely and track movement history.</p>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={fetchProducts} className="flex items-center gap-2 px-3 py-2 bg-white border border-gray-200 rounded-xl text-sm font-medium hover:bg-gray-50 transition shadow-sm">
                        <RefreshCw className="w-3.5 h-3.5" />
                    </button>
                    {hasPendingEdits && (
                        <button onClick={handleBulkSave} disabled={isSavingBulk} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl text-sm font-bold shadow-lg shadow-blue-500/20 hover:bg-blue-700 transition disabled:opacity-50">
                            {isSavingBulk ? <Loader2 className="w-4 h-4 animate-spin"/> : <Save className="w-4 h-4" />}
                            Update {Object.keys(pendingEdits).length} Products
                        </button>
                    )}
                </div>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                    { label: 'In Stock', value: inStock.length, color: 'emerald', icon: CheckCircle2, filter: 'all' },
                    { label: 'Low Stock', value: lowStock.length, color: 'orange', icon: TrendingDown, filter: 'low' },
                    { label: 'Out of Stock', value: outOfStock.length, color: 'red', icon: XCircle, filter: 'out' },
                    { label: 'Archived', value: archivedProducts.length, color: 'gray', icon: Archive, filter: 'archived' },
                ].map(s => (
                    <button
                        key={s.label}
                        onClick={() => setFilter(s.filter as any)}
                        className={`bg-white border rounded-2xl p-4 shadow-sm text-left transition-all hover:shadow-md ${filter === s.filter ? 'ring-2 ring-blue-500 border-blue-500' : 'border-gray-100'}`}
                    >
                        <div className="flex items-center gap-2 mb-1">
                            <s.icon className={`w-4 h-4 text-${s.color}-500`} />
                            <p className="text-xs text-gray-400 font-medium">{s.label}</p>
                        </div>
                        <p className={`text-2xl lg:text-3xl font-black text-${s.color}-600`}>{s.value}</p>
                    </button>
                ))}
            </div>

            {/* Smart Alerts */}
            {outOfStock.length > 0 && filter !== 'archived' && (
                <div className="bg-red-50 border border-red-200 rounded-2xl p-4 flex gap-4">
                    <div className="w-9 h-9 bg-red-100 rounded-xl flex items-center justify-center flex-shrink-0">
                        <Bell className="w-4 h-4 text-red-600" />
                    </div>
                    <div>
                        <p className="text-sm font-bold text-red-800 mb-1">{outOfStock.length} product(s) entirely out of stock!</p>
                        <div className="flex flex-wrap gap-2 mt-2">
                            {outOfStock.slice(0, 3).map(p => (
                                <button key={p.id} onClick={() => setRestockProduct(p)} className="inline-flex items-center gap-1 bg-red-600 hover:bg-red-700 transition text-white text-xs font-semibold px-2.5 py-1 rounded-lg">
                                    <Plus className="w-3 h-3" /> Restock {p.title}
                                </button>
                            ))}
                            {outOfStock.length > 3 && <span className="text-xs text-red-500 self-center">+{outOfStock.length - 3} more</span>}
                        </div>
                    </div>
                </div>
            )}

            {/* Search + Filter */}
            <div className="bg-white border border-gray-100 rounded-xl shadow-sm flex items-center gap-3 px-4 py-3 min-w-[200px]">
                <Search className="w-4 h-4 text-gray-300 flex-shrink-0" />
                <input
                    type="text"
                    placeholder="Search products by SKU or title..."
                    className="flex-1 bg-transparent text-sm text-gray-700 placeholder-gray-300 outline-none"
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                />
                {search && <button onClick={() => setSearch('')} className="text-gray-300 hover:text-gray-500"><X className="w-4 h-4" /></button>}
            </div>

            {/* Product Stock Table */}
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm">
                        <thead>
                            <tr className="border-b border-gray-100 bg-gray-50/60">
                                <th className="px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-widest">Product</th>
                                <th className="px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-widest text-center">Status</th>
                                <th className="px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-widest text-center">Threshold</th>
                                <th className="px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-widest text-center">Stock Qty</th>
                                <th className="px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-widest text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {filtered.map(product => {
                                const threshold = getDisplayValue(product, 'low_stock_threshold');
                                const qty = getDisplayValue(product, 'stock_quantity');
                                const isOut = qty === 0;
                                const isLow = !isOut && qty <= threshold;
                                const hasEdit = !!pendingEdits[product.id];

                                return (
                                    <tr key={product.id} className={`transition-colors ${!product.is_active ? 'opacity-60 bg-gray-50' : 'hover:bg-blue-50/20'}`}>
                                        <td className="px-5 py-3">
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 bg-gray-100 rounded-lg flex-shrink-0 overflow-hidden border border-gray-100">
                                                    {product.image_urls?.[0] ? <img src={product.image_urls[0]} alt="" className="object-cover w-full h-full" /> : <PackageOpen className="w-4 h-4 text-gray-300 m-3" />}
                                                </div>
                                                <div>
                                                    <p className="font-bold text-gray-900 text-sm">{product.title}</p>
                                                    <p className="text-xs text-blue-500 font-mono mt-0.5">{product.sku || 'NO-SKU'}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-5 py-3 text-center">
                                            {!product.is_active ? (
                                                <span className="text-gray-500 bg-gray-100 text-xs px-2 py-1 rounded font-bold">Archived</span>
                                            ) : isOut ? (
                                                <span className="text-red-700 bg-red-100 text-xs px-2 py-1 rounded font-bold">Out of Stock</span>
                                            ) : isLow ? (
                                                <span className="text-orange-700 bg-orange-100 text-xs px-2 py-1 rounded font-bold">Low Stock</span>
                                            ) : (
                                                <span className="text-emerald-700 bg-emerald-100 text-xs px-2 py-1 rounded font-bold">Healthy</span>
                                            )}
                                        </td>
                                        <td className="px-5 py-3 text-center">
                                            <input
                                                type="number"
                                                min={0}
                                                value={threshold}
                                                onChange={(e) => handleEditField(product.id, 'low_stock_threshold', e.target.value)}
                                                className={`w-16 text-center px-1 py-1 rounded border text-xs bg-gray-50 focus:bg-white focus:ring-1 focus:ring-blue-500`}
                                            />
                                        </td>
                                        <td className="px-5 py-3 text-center">
                                            <div className="flex justify-center items-center gap-2">
                                                <input
                                                    type="number"
                                                    min={0}
                                                    value={qty}
                                                    onChange={(e) => handleEditField(product.id, 'stock_quantity', e.target.value)}
                                                    className={`w-20 text-center px-2 py-1.5 rounded-lg border text-sm font-black font-mono shadow-inner ${hasEdit ? 'border-blue-400 bg-blue-50 text-blue-800' : 'border-gray-200 bg-white'}`}
                                                />
                                            </div>
                                        </td>
                                        <td className="px-5 py-3 text-right">
                                            <div className="flex items-center justify-end gap-1.5">
                                                {product.is_active && isOut && (
                                                    <button onClick={() => setRestockProduct(product)} className="text-xs font-bold text-white bg-blue-600 hover:bg-blue-700 px-2 py-1.5 rounded shadow flex items-center gap-1 transition">
                                                        Restock
                                                    </button>
                                                )}
                                                <button onClick={() => fetchHistoryEvents(product)} className="w-8 h-8 flex items-center justify-center rounded-lg text-gray-500 hover:bg-gray-100 transition" title="View History">
                                                    <History className="w-4 h-4" />
                                                </button>
                                                <button onClick={() => toggleArchive(product.id, product.is_active)} className="w-8 h-8 flex items-center justify-center rounded-lg text-gray-400 hover:text-red-500 hover:bg-red-50 transition" title={product.is_active ? "Archive Product" : "Unarchive"}>
                                                    {product.is_active ? <Archive className="w-4 h-4" /> : <RotateCcw className="w-4 h-4" />}
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                            {filtered.length === 0 && (
                                <tr>
                                    <td colSpan={5} className="px-5 py-12 text-center text-gray-500">No products match your filters.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Quick Restock Modal */}
            {restockProduct && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden">
                        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                            <h3 className="font-bold text-lg">Quick Restock</h3>
                            <button onClick={() => setRestockProduct(null)} className="text-gray-400 hover:bg-gray-100 p-1 rounded-lg"><X className="w-5 h-5"/></button>
                        </div>
                        <form onSubmit={handleQuickRestockSubmit} className="p-6 space-y-5">
                            <div className="flex gap-3 items-center border border-gray-100 p-3 rounded-xl bg-gray-50">
                                {restockProduct.image_urls?.[0] ? <img src={restockProduct.image_urls[0]} alt="" className="w-12 h-12 rounded object-cover" /> : <div className="w-12 h-12 bg-white rounded border flex items-center justify-center"><PackageOpen className="w-5 h-5 text-gray-300"/></div>}
                                <div>
                                    <p className="font-bold text-sm text-gray-900">{restockProduct.title}</p>
                                    <p className="text-xs text-blue-600 font-mono">{restockProduct.sku}</p>
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-1">Received Quantity (Delta) <span className="text-red-500">*</span></label>
                                <input type="number" min="1" required value={restockDelta} onChange={(e) => setRestockDelta(parseInt(e.target.value) || 0)} className="w-full border border-gray-300 rounded-lg p-3 text-lg font-black text-center focus:ring-2 focus:ring-blue-500 outline-none"/>
                                <p className="text-xs text-gray-500 mt-1">This amount will be added to the current stock.</p>
                            </div>

                            <div>
                                <label className="block text-sm font-semibold text-gray-700 mb-1">Restock Note / Supplier (Optional)</label>
                                <input type="text" value={restockNote} onChange={(e) => setRestockNote(e.target.value)} placeholder="e.g. Shipment from DHL" className="w-full border border-gray-300 rounded-lg p-2.5 text-sm outline-none focus:border-blue-500"/>
                            </div>

                            <div className="pt-2">
                                <button type="submit" disabled={isRestocking} className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-xl transition flex justify-center items-center gap-2 disabled:opacity-50">
                                    {isRestocking ? 'Restocking...' : 'Add Stock Now'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* History Modal */}
            {historyProduct && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-white rounded-2xl w-full max-w-xl shadow-2xl overflow-hidden flex flex-col max-h-[85vh]">
                        <div className="px-6 py-4 border-b border-gray-100 flex items-center justify-between">
                            <div>
                                <h3 className="font-bold text-lg">Stock History</h3>
                                <p className="text-xs text-gray-500 truncate mt-0.5">{historyProduct.title} ({historyProduct.sku})</p>
                            </div>
                            <button onClick={() => setHistoryProduct(null)} className="text-gray-400 hover:bg-gray-100 p-1 rounded-lg"><X className="w-5 h-5"/></button>
                        </div>
                        <div className="p-6 overflow-y-auto bg-gray-50 flex-1">
                            {loadingHistory ? (
                                <div className="py-12 flex justify-center"><Loader2 className="w-6 h-6 animate-spin text-blue-500"/></div>
                            ) : historyEvents.length === 0 ? (
                                <div className="py-12 text-center text-gray-500 text-sm">No historical stock movements exist for this product.</div>
                            ) : (
                                <div className="space-y-3">
                                    {historyEvents.map((evt) => (
                                        <div key={evt.id} className="bg-white border border-gray-200 p-3 rounded-xl shadow-sm flex items-center gap-4">
                                            <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${evt.quantity_delta > 0 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>
                                                {evt.quantity_delta > 0 ? <TrendingDown className="w-5 h-5 rotate-180" /> : <TrendingDown className="w-5 h-5" />}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <p className="font-black text-sm">{evt.quantity_delta > 0 ? '+' : ''}{evt.quantity_delta} units</p>
                                                <p className="text-xs text-gray-500 truncate">{evt.reason.replace(/_/g, ' ')} {evt.reference_id && `(#${evt.reference_id})`}</p>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-xs font-mono bg-gray-100 px-2 py-0.5 rounded text-gray-600">{evt.previous_stock} → {evt.new_stock}</p>
                                                <p className="text-[10px] text-gray-400 mt-1">{new Date(evt.created_at).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { useParams, useSearchParams } from 'next/navigation';
import { createClient } from '@/utils/supabase/client';
import { Clock, Store, Plus, Palette, Eye, Package, AlertTriangle } from 'lucide-react';
import { buildStorefrontUrl } from '@/lib/storefront';

interface Shop {
    id: string;
    shop_name: string;
    route_path: string;
    is_approved: boolean;
    primary_color: string;
}

interface OrderStats {
    total: number;
    processing: number;
    revenue: number;
}

interface LowStockProduct {
    id: string;
    title: string;
    stock_quantity: number;
    low_stock_threshold: number;
}

export default function DashboardOverview() {
    const params = useParams<{ shopSlug?: string }>();
    const searchParams = useSearchParams();
    const supabase = createClient();
    const [shop, setShop] = useState<Shop | null>(null);
    const [userName, setUserName] = useState('');
    const [orderStats, setOrderStats] = useState<OrderStats>({ total: 0, processing: 0, revenue: 0 });
    const [lowStockCount, setLowStockCount] = useState(0);
    const [lowStockProducts, setLowStockProducts] = useState<LowStockProduct[]>([]);
    const [loading, setLoading] = useState(true);

    const createdRoute = searchParams.get('route');
    const createdUrl = searchParams.get('url');
    const hasCreatedFlag = searchParams.get('created') === '1';
    const storefrontUrl = shop ? buildStorefrontUrl(shop.route_path) : null;
    const requestedSlug = params?.shopSlug;

    const fetchData = useCallback(async () => {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        // Get owner details
        const { data: owner } = await supabase
            .from('owners')
            .select('full_name')
            .eq('id', user.id)
            .maybeSingle();
        setUserName(owner?.full_name || user.email?.split('@')[0] || 'Shop Owner');

        // Get shop scoped to owner and optional slug route.
        let shopQuery = supabase
            .from('shops')
            .select('id, shop_name, route_path, is_approved, primary_color')
            .eq('owner_id', user.id)
            .order('created_at', { ascending: false })
            .limit(1);

        if (requestedSlug) {
            shopQuery = shopQuery.eq('route_path', requestedSlug);
        }

        const { data: shopData } = await shopQuery.maybeSingle();
        setShop(shopData);

        if (shopData) {
            // Get orders
            const { data: orders } = await supabase
                .from('orders')
                .select('total_amount, status')
                .eq('shop_id', shopData.id);

            const all = orders || [];
            setOrderStats({
                total: all.length,
                processing: all.filter(o => o.status === 'processing').length,
                revenue: all.reduce((sum, o) => sum + Number(o.total_amount), 0),
            });

            // Get low stock products
            const { data: products } = await supabase
                .from('products')
                .select('id, title, stock_quantity, low_stock_threshold')
                .eq('shop_id', shopData.id);

            const pList = products || [];
            const lowStockItems = pList.filter(p => p.stock_quantity <= p.low_stock_threshold);
            setLowStockCount(lowStockItems.length);
            setLowStockProducts(lowStockItems.sort((a, b) => a.stock_quantity - b.stock_quantity));
        }

        setLoading(false);
    }, [requestedSlug, supabase]);

    useEffect(() => { fetchData(); }, [fetchData]);

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-8 min-h-screen">
                <div className="text-center">
                    <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
                    <p className="text-gray-400 text-sm">Loading your dashboard...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="p-6 lg:p-8 space-y-6 max-w-7xl mx-auto">

            {/* Pending status banner */}
            {shop && !shop.is_approved && (
                <div className="bg-amber-50 border border-amber-200 rounded-2xl p-5 flex items-start gap-4">
                    <Clock className="text-amber-500 mt-0.5 w-6 h-6 flex-shrink-0" />
                    <div className="flex-1">
                        <h3 className="font-bold text-amber-900">Your shop is under review</h3>
                        <p className="text-sm text-amber-700 mt-1">
                            Your shop has been created and is pending admin approval. Once approved, your shop at{' '}
                            <span className="font-mono font-semibold">/shop/{shop.route_path}</span> will go live for customers.
                            You can still preview and customize it in the meantime.
                        </p>
                    </div>
                    <div className="flex flex-col sm:flex-row gap-2">
                        {storefrontUrl && (
                            <a
                                href={storefrontUrl}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-sm bg-white text-amber-700 px-4 py-2 rounded-lg font-medium border border-amber-300 hover:bg-amber-100 transition whitespace-nowrap"
                            >
                                Preview Store
                            </a>
                        )}
                        <Link href="/dashboard/settings" className="text-sm bg-amber-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-amber-700 transition whitespace-nowrap">
                            Customize Store
                        </Link>
                    </div>
                </div>
            )}

            {hasCreatedFlag && createdRoute && (
                <div className="bg-blue-50 border border-blue-200 rounded-2xl p-4 flex flex-wrap items-center justify-between gap-3">
                    <div>
                        <p className="text-sm font-semibold text-blue-900">Shop created successfully</p>
                        <p className="text-sm text-blue-700">
                            Your storefront path is <span className="font-mono font-semibold">/shop/{createdRoute}</span>
                        </p>
                    </div>
                    {createdUrl && (
                        <a
                            href={createdUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-sm bg-blue-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-blue-700 transition"
                        >
                            Open Storefront ↗
                        </a>
                    )}
                </div>
            )}

            {/* Verified banner */}
            {shop?.is_approved && (
                <div className="bg-green-50 border border-green-200 rounded-2xl p-4 flex items-center gap-4">
                    <span className="relative flex h-3 w-3">
                        <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75" />
                        <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500" />
                    </span>
                    <p className="text-green-800 font-medium text-sm flex-1">
                        Your shop is <strong>Live</strong> at{' '}
                        <a href={storefrontUrl || '#'} target="_blank" rel="noopener noreferrer" className="underline font-mono">/shop/{shop.route_path}</a>
                    </p>
                    <a href={storefrontUrl || '#'} target="_blank" rel="noopener noreferrer" className="text-sm bg-green-700 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-800 transition">
                        View Live Store ↗
                    </a>
                </div>
            )}

            {/* Header */}
            <div>
                <h1 className="text-2xl font-bold text-gray-900">Welcome back, {userName} 👋</h1>
                <p className="text-gray-500 text-sm mt-1">{shop?.shop_name || 'Your shop'} — Dashboard Overview</p>
            </div>

            {/* Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-gray-500 text-sm font-medium">Total Revenue</p>
                    <p className="text-3xl font-black text-gray-900 mt-2">Rs. {orderStats.revenue.toLocaleString()}</p>
                    <p className="text-xs text-gray-400 mt-1">From {orderStats.total} orders</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-gray-500 text-sm font-medium">Active Orders</p>
                    <p className="text-3xl font-black text-gray-900 mt-2">{orderStats.processing}</p>
                    <p className="text-xs text-orange-500 font-medium mt-1">{orderStats.processing} pending fulfillment</p>
                </div>
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                    <p className="text-gray-500 text-sm font-medium">Low Stock Alerts</p>
                    <p className={`text-3xl font-black mt-2 ${lowStockCount > 0 ? 'text-red-600' : 'text-gray-900'}`}>{lowStockCount}</p>
                    {lowStockCount > 0 ? (
                        <Link href="/dashboard/products" className="text-xs text-red-600 font-medium mt-1 hover:underline block">Restock now →</Link>
                    ) : (
                        <p className="text-xs text-green-600 mt-1">All products stocked ✓</p>
                    )}
                </div>
            </div>

            {/* Smart Inventory Alerts Widget */}
            {lowStockProducts.length > 0 && (
                <div className="bg-red-50 border border-red-100 rounded-2xl p-6 shadow-sm">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center text-red-600">
                            <AlertTriangle className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="font-bold text-red-900 text-lg">Inventory Action Required</h3>
                            <p className="text-red-700 text-sm">{lowStockProducts.length} items are running low or out of stock.</p>
                        </div>
                    </div>
                    <div className="space-y-3">
                        {lowStockProducts.slice(0, 3).map((product, idx) => (
                            <div key={idx} className="bg-white border text-sm border-red-100 rounded-xl p-3 flex justify-between items-center shadow-sm">
                                <div className="font-medium text-gray-900">{product.title}</div>
                                <div className="flex items-center gap-3">
                                    <span className={`px-2 py-1 rounded-md text-xs font-semibold ${product.stock_quantity === 0 ? 'bg-red-100 text-red-700' : 'bg-orange-100 text-orange-700'}`}>
                                        {product.stock_quantity === 0 ? 'Out of Stock' : `${product.stock_quantity} Left`}
                                    </span>
                                    <Link href="/dashboard/products" className="text-blue-600 font-medium hover:underline text-xs">Manage</Link>
                                </div>
                            </div>
                        ))}
                    </div>
                    {lowStockProducts.length > 3 && (
                        <Link href="/dashboard/products" className="text-sm font-medium text-red-700 hover:text-red-900 mt-4 inline-block hover:underline">
                            View all {lowStockProducts.length} alerts →
                        </Link>
                    )}
                </div>
            )}

            {/* Quick Actions */}
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
                {[
                    { label: 'Add Product', href: '/dashboard/products', icon: Plus },
                    { label: 'Storefront Settings', href: '/dashboard/settings', icon: Palette },
                    { label: 'Preview Store', href: storefrontUrl || '/onboarding', icon: Eye, external: !!storefrontUrl },
                    { label: 'View Orders', href: '/dashboard/orders', icon: Package },
                ].map((action) => (
                    <Link
                        key={action.label}
                        href={action.href}
                        target={action.external ? '_blank' : undefined}
                        className="bg-white border border-gray-100 rounded-2xl p-5 text-center hover:shadow-md hover:border-gray-200 transition group flex flex-col items-center"
                    >
                        <action.icon className="w-8 h-8 text-blue-600 mb-3 group-hover:scale-110 transition-transform" strokeWidth={1.5} />
                        <p className="text-sm font-medium text-gray-700">{action.label}</p>
                    </Link>
                ))}
            </div>

            {!shop && (
                <div className="bg-blue-50 border border-blue-100 rounded-2xl p-8 text-center flex flex-col items-center">
                    <div className="w-16 h-16 bg-blue-100 rounded-2xl flex items-center justify-center mb-4 text-blue-600">
                        <Store className="w-8 h-8" />
                    </div>
                    <h3 className="text-lg font-bold text-blue-900 mb-2">You don&apos;t have a shop yet!</h3>
                    <p className="text-blue-700 text-sm mb-5">Complete the onboarding process to create your storefront.</p>
                    <Link href="/onboarding" className="bg-blue-600 text-white px-6 py-3 rounded-xl font-medium hover:bg-blue-700 transition">
                        Start Shop Setup →
                    </Link>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect, useRef } from 'react';
import { createClient } from '@/utils/supabase/client';
import { useRouter } from 'next/navigation';
import { PackageSearch, Plus, Search, AlertTriangle, Edit, Trash2, CheckCircle2, X, Loader2, UploadCloud, Image, ListPlus, Copy, Wand2 } from 'lucide-react';
import { uploadToShopAssets } from '@/lib/storage/shopAssets';
import {
    DEFAULT_PRODUCT_UNIT,
    DEFAULT_STOCK_UNIT,
    DEFAULT_UNIT_VALUE,
    formatPriceWithUnit,
    formatStockWithUnit,
    getUnitLabel,
    normalizeSellingUnit,
    normalizeStockUnit,
    normalizeUnitValue,
    PRODUCT_UNITS,
    productUpsertSchema,
    type ProductUnit,
} from '@/lib/products';

interface VariantState {
    id?: string;
    sku: string;
    options: Record<string, string>;
    price_override: string;
    compare_at_price: string;
    stock_quantity: string;
    image_url: string;
}

interface ProductRecord {
    id: string;
    title: string;
    description: string | null;
    price: number;
    compare_at_price?: number | null;
    selling_unit_value: number;
    selling_unit: ProductUnit;
    stock_quantity: number;
    stock_unit: ProductUnit;
    low_stock_threshold: number | null;
    image_urls: string[];
    has_variants?: boolean;
    variation_options?: { name: string; raw_values: string }[];
    product_variants?: VariantState[];
}

interface ProductFormState {
    title: string;
    description: string;
    price: string;
    compare_at_price: string;
    selling_unit_value: string;
    selling_unit: ProductUnit;
    stock_quantity: string;
    stock_unit: ProductUnit;
    low_stock_threshold: string;
    image_urls: string[];
    has_variants: boolean;
    variation_options: { name: string; raw_values: string }[];
    variants: VariantState[];
}

export default function ProductsDashboard() {
    const supabase = createClient();
    const router = useRouter();
    const [products, setProducts] = useState<ProductRecord[]>([]);
    const [shopId, setShopId] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [filterMode, setFilterMode] = useState<'all' | 'low_stock' | 'sale'>('all');

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState<ProductRecord | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [uploadError, setUploadError] = useState<string | null>(null);
    const [formError, setFormError] = useState<string | null>(null);
    const [uploadingVariantIndex, setUploadingVariantIndex] = useState<number | null>(null);
    const [primaryGrouping, setPrimaryGrouping] = useState<string>('');
    const [formData, setFormData] = useState<ProductFormState>({
        title: '', description: '', price: '', compare_at_price: '', selling_unit_value: DEFAULT_UNIT_VALUE.toString(), selling_unit: DEFAULT_PRODUCT_UNIT, stock_quantity: '0', stock_unit: DEFAULT_STOCK_UNIT, low_stock_threshold: '5', image_urls: [],
        has_variants: false, variation_options: [], variants: []
    });

    // UI Sale Maker State
    const [saleConfig, setSaleConfig] = useState({ enabled: false, type: 'percent' as 'percent'|'fixed', value: '' });

    // Sync Sale Value into formData price and Variant prices
    useEffect(() => {
        if (saleConfig.enabled && formData.compare_at_price && saleConfig.value) {
            const orig = Number(formData.compare_at_price);
            const val = Number(saleConfig.value);
            if (!isNaN(orig) && !isNaN(val)) {
                let newPrice = orig;
                let discountPercent = 0;

                if (saleConfig.type === 'percent') {
                     newPrice = orig - (orig * (val / 100));
                     discountPercent = val;
                } else if (saleConfig.type === 'fixed') {
                     newPrice = orig - val;
                     discountPercent = (val / orig) * 100;
                }
                const formattedPrice = newPrice > 0 ? newPrice.toFixed(2) : '0.00';

                setFormData(prev => {
                    let updated = false;
                    const next = { ...prev };

                    if (prev.price !== formattedPrice) {
                        next.price = formattedPrice;
                        updated = true;
                    }

                    if (prev.has_variants && prev.variants.length > 0) {
                        const newVariants = prev.variants.map(v => {
                            // Only apply if the variant has a compare_at_price OR use the base compare_at_price as fallback
                            const varOrig = v.compare_at_price ? Number(v.compare_at_price) : orig;
                            if (!isNaN(varOrig) && varOrig > 0) {
                                const varNewPrice = varOrig - (varOrig * (discountPercent / 100));
                                const formattedVarPrice = varNewPrice > 0 ? varNewPrice.toFixed(2) : '0.00';
                                if (v.price_override !== formattedVarPrice || v.compare_at_price !== String(varOrig)) {
                                    updated = true;
                                    return { ...v, compare_at_price: String(varOrig), price_override: formattedVarPrice };
                                }
                            }
                            return v;
                        });
                        if (updated) {
                            next.variants = newVariants;
                        }
                    }

                    return updated ? next : prev;
                });
            }
        }
    }, [saleConfig.enabled, saleConfig.type, saleConfig.value, formData.compare_at_price]);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const variantFileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        async function fetch() {
            setLoading(true);
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                router.replace('/login?next=/dashboard/products');
                setLoading(false);
                return;
            }

            const { data: owner } = await supabase
                .from('owners')
                .select('role')
                .eq('id', user.id)
                .maybeSingle<{ role: string | null }>();

            if (owner?.role !== 'shop_owner' && owner?.role !== 'admin') {
                router.replace('/');
                setLoading(false);
                return;
            }

            const { data: shop } = await supabase.from('shops').select('id').eq('owner_id', user.id).single();
            if (shop) {
                setShopId(shop.id);
                const { data } = await supabase.from('products').select('*, product_variants(*)').eq('shop_id', shop.id).order('created_at', { ascending: false });
                const normalizedProducts = (data || []).map((product) => ({
                    ...product,
                    selling_unit_value: normalizeUnitValue(product.selling_unit_value ?? product.unit_value),
                    selling_unit: normalizeSellingUnit(product.selling_unit ?? product.unit),
                    stock_quantity: Number(product.stock_quantity ?? 0),
                    stock_unit: normalizeStockUnit(product.stock_unit ?? product.selling_unit ?? product.unit),
                }));
                setProducts(normalizedProducts);
            }
            setLoading(false);
        }
        fetch();
    }, [supabase, router]);

    const filteredProducts = products.filter(p => {
        if (!p.title.toLowerCase().includes(search.toLowerCase())) return false;
        if (filterMode === 'low_stock') return p.stock_quantity > 0 && p.stock_quantity <= (p.low_stock_threshold || 5);
        if (filterMode === 'sale') {
           const hasSale = p.compare_at_price != null && p.compare_at_price > p.price;
           const hasVariantSale = p.has_variants && p.product_variants?.some(v => v.compare_at_price != null && (v.price_override ? Number(v.compare_at_price) > Number(v.price_override) : Number(v.compare_at_price) > p.price));
           return hasSale || hasVariantSale;
        }
        return true;
    });

    const openModal = (product: ProductRecord | null = null) => {
        setEditingProduct(product);
        setUploadError(null);
        setFormError(null);

        let saleEnabled = false;
        let saleType: 'percent' | 'fixed' = 'percent';
        let saleVal = '';
        if (product && product.compare_at_price && Number(product.compare_at_price) > product.price) {
            saleEnabled = true;
            const orig = Number(product.compare_at_price);
            const curr = product.price;
            const diff = orig - curr;
            const pct = (diff / orig) * 100;
            if (Number.isInteger(pct)) {
                saleVal = pct.toString();
            } else {
                saleType = 'fixed';
                saleVal = diff.toFixed(2);
            }
        }
        setSaleConfig({ enabled: saleEnabled, type: saleType, value: saleVal });

        setFormData(product ? {
            title: product.title, description: product.description || '', price: product.price.toString(), compare_at_price: product.compare_at_price ? product.compare_at_price.toString() : '',
            selling_unit_value: normalizeUnitValue(product.selling_unit_value).toString(),
            selling_unit: normalizeSellingUnit(product.selling_unit),
            stock_quantity: Number(product.stock_quantity || 0).toString(),
            stock_unit: normalizeStockUnit(product.stock_unit),
            low_stock_threshold: Number(product.low_stock_threshold || 5).toString(), image_urls: product.image_urls || [],
            has_variants: product.has_variants || false,
            // Convert legacy generic array back to raw_values
            variation_options: (product.variation_options || []).map((o: any) => ({ name: o.name, raw_values: Array.isArray(o.values) ? o.values.join(', ') : o.values || o.raw_values || '' })),
            variants: (product.product_variants || []).map(v => ({ ...v, price_override: v.price_override ? String(v.price_override) : '', compare_at_price: v.compare_at_price ? String(v.compare_at_price) : '', stock_quantity: String(v.stock_quantity || 0), image_url: v.image_url || '' }))
        } : {
            title: '', description: '', price: '', compare_at_price: '', selling_unit_value: DEFAULT_UNIT_VALUE.toString(), selling_unit: DEFAULT_PRODUCT_UNIT,
            stock_quantity: '0', stock_unit: DEFAULT_STOCK_UNIT, low_stock_threshold: '5', image_urls: [],
            has_variants: false, variation_options: [], variants: []
        });
        setIsModalOpen(true);
    };

    const closeModal = () => { setIsModalOpen(false); setEditingProduct(null); };

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !shopId) return;

        setUploadError(null);
        setIsUploading(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `product-${Date.now()}-${Math.random().toString(36).slice(2)}.${fileExt}`;
            const filePath = `${shopId}/products/${fileName}`;

            const { publicUrl } = await uploadToShopAssets({
                supabase,
                file,
                filePath,
                upsert: true,
            });

            setFormData(prev => ({ ...prev, image_urls: [publicUrl, ...prev.image_urls.filter(u => u !== publicUrl)] }));
        } catch (err: unknown) {
            const message = err instanceof Error ? err.message : 'Upload failed. Please try again.';
            setUploadError(message);
        } finally {
            setIsUploading(false);
            if (fileInputRef.current) fileInputRef.current.value = '';
        }
    };

    const removeImage = (url: string) => {
        setFormData(prev => ({ ...prev, image_urls: prev.image_urls.filter(u => u !== url) }));
    };

    const handleVariantImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !shopId || uploadingVariantIndex === null) return;

        setUploadError(null);
        setIsUploading(true);
        try {
            const fileExt = file.name.split('.').pop();
            const fileName = `variant-${Date.now()}-${Math.random().toString(36).slice(2)}.${fileExt}`;
            const filePath = `${shopId}/products/variants/${fileName}`;

            const { publicUrl } = await uploadToShopAssets({ supabase, file, filePath, upsert: true });

            const nextVariants = [...formData.variants];
            nextVariants[uploadingVariantIndex].image_url = publicUrl;
            setFormData(prev => ({ ...prev, variants: nextVariants }));
        } catch (err: unknown) {
             setUploadError(err instanceof Error ? err.message : 'Variant upload failed.');
        } finally {
            setIsUploading(false);
            setUploadingVariantIndex(null);
            if (variantFileInputRef.current) variantFileInputRef.current.value = '';
        }
    };

    const addVariationOption = () => {
        setFormData(prev => ({ ...prev, variation_options: [...prev.variation_options, { name: '', raw_values: '' }] }));
    };

    const updateVariationOption = (idx: number, field: 'name' | 'raw_values', val: string) => {
        const newOpts = [...formData.variation_options];
        newOpts[idx] = { ...newOpts[idx], [field]: val };
        setFormData(prev => ({ ...prev, variation_options: newOpts }));
    };

    const removeVariationOption = (idx: number) => {
        setFormData(prev => ({ ...prev, variation_options: prev.variation_options.filter((_, i) => i !== idx) }));
    };

    const generateCombinations = () => {
        const parsedOptions = formData.variation_options.map(o => ({
            name: o.name.trim(),
            values: o.raw_values.split(',').map(s => s.trim()).filter(Boolean)
        }));

        const options = parsedOptions.filter(o => o.name && o.values.length > 0);
        if (options.length === 0) return;

        let combos: Record<string, string>[] = [{}];
        for (const opt of options) {
            const nextCombos: Record<string, string>[] = [];
            for (const combo of combos) {
                for (const val of opt.values) {
                    nextCombos.push({ ...combo, [opt.name]: val });
                }
            }
            combos = nextCombos;
        }

        const newVariants: VariantState[] = combos.map(combo => {
            const existing = formData.variants.find(v => JSON.stringify(v.options) === JSON.stringify(combo));
            return existing || { sku: '', options: combo, price_override: '', compare_at_price: '', stock_quantity: '0', image_url: '' };
        });

        setFormData(prev => ({ ...prev, variants: newVariants }));
    };

    const getSupabaseErrorMessage = (err: unknown): string => {
        if (err instanceof Error) return err.message;
        if (err && typeof err === 'object') {
            const maybe = err as { message?: unknown; details?: unknown; hint?: unknown; code?: unknown };
            const parts = [maybe.message, maybe.details, maybe.hint, maybe.code]
                .filter((v): v is string => typeof v === 'string' && v.trim().length > 0);
            if (parts.length > 0) return parts.join(' | ');
        }
        return 'Failed to save product.';
    };

    const isProductsSchemaMismatch = (message: string): boolean => {
        const lower = message.toLowerCase();
        return (
            (lower.includes('column') && (lower.includes('selling_unit') || lower.includes('stock_unit') || lower.includes('selling_unit_value'))) ||
            lower.includes('schema cache') ||
            lower.includes('pgrst204')
        );
    };

    const handleSave = async () => {
        if (!shopId) return;
        setFormError(null);
        setIsSaving(true);
        try {
            const mappedVariationOptions = formData.variation_options.map(o => ({
                name: o.name.trim(),
                values: o.raw_values.split(',').map(s => s.trim()).filter(Boolean)
            })).filter(o => o.name && o.values.length > 0);

            const parsed = productUpsertSchema.safeParse({
                ...formData,
                image_urls: formData.image_urls.filter(u => u.trim() !== ''),
                variation_options: mappedVariationOptions,
            });

            if (!parsed.success) {
                setFormError(parsed.error.issues[0]?.message || 'Invalid product details.');
                return;
            }

            const res = await fetch('/api/products/upsert', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    id: editingProduct?.id,
                    ...parsed.data
                })
            });

            const json = await res.json();
            if (!res.ok) throw new Error(json.error || 'Failed to save product');

            const savedProduct = {
                ...json.product,
                product_variants: json.product.has_variants ? parsed.data.variants : [],
                selling_unit_value: normalizeUnitValue(json.product.selling_unit_value),
                selling_unit: normalizeSellingUnit(json.product.selling_unit),
                stock_quantity: Number(json.product.stock_quantity ?? 0),
                stock_unit: normalizeStockUnit(json.product.stock_unit),
            };

            if (editingProduct) {
                setProducts(products.map(p => p.id === savedProduct.id ? savedProduct : p));
            } else {
                setProducts([savedProduct, ...products]);
            }
            closeModal();

        } catch (err: unknown) {
            const message = err instanceof Error ? err.message : 'Failed to save product.';
            setFormError(message);
        } finally {
            setIsSaving(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Delete this product?')) return;
        await supabase.from('products').delete().eq('id', id);
        setProducts(products.filter(p => p.id !== id));
    };

    if (loading) {
        return (
            <div className="flex-1 flex items-center justify-center p-8 min-h-[60vh]">
                <div className="text-center">
                    <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-3" />
                    <p className="text-gray-400 text-sm">Loading products...</p>
                </div>
            </div>
        );
    }

    const lowStock = products.filter(p => p.stock_quantity > 0 && p.stock_quantity <= (p.low_stock_threshold || 5)).length;
    const outOfStock = products.filter(p => p.stock_quantity === 0).length;

    return (
        <div className="p-6 lg:p-8 max-w-7xl mx-auto space-y-6">

            {/* Page Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Products</h1>
                    <p className="text-sm text-gray-400 mt-0.5">Manage your inventory, pricing, and stock levels</p>
                </div>
                <button
                    onClick={() => openModal()}
                    className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl text-sm font-semibold flex items-center gap-2 transition shadow-sm shadow-blue-200"
                >
                    <Plus className="w-4 h-4" />
                    Add Product
                </button>
            </div>

            {/* Stats Strip */}
            <div className="grid grid-cols-3 gap-4">
                {[
                    { label: 'Total Products', value: products.length, color: 'blue' },
                    { label: 'Low Stock', value: lowStock, color: 'orange' },
                    { label: 'Out of Stock', value: outOfStock, color: 'red' },
                ].map(s => (
                    <div key={s.label} className="bg-white border border-gray-100 rounded-2xl p-4 shadow-sm">
                        <p className="text-xs text-gray-400 font-medium mb-1">{s.label}</p>
                        <p className={`text-2xl font-black ${s.color === 'blue' ? 'text-blue-600' : s.color === 'orange' ? 'text-orange-500' : 'text-red-600'}`}>{s.value}</p>
                    </div>
                ))}
            </div>

            {/* Search & Filters */}
            <div className="flex flex-col sm:flex-row gap-4 items-center">
                <div className="bg-white border border-gray-100 rounded-xl shadow-sm flex items-center gap-3 px-4 py-3 flex-1 w-full">
                    <Search className="w-4 h-4 text-gray-300 flex-shrink-0" />
                    <input
                        type="text"
                        placeholder="Search products..."
                        className="flex-1 bg-transparent text-sm text-gray-700 placeholder-gray-300 outline-none"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                    />
                    {search && (
                        <button onClick={() => setSearch('')} className="text-gray-300 hover:text-gray-500">
                            <X className="w-4 h-4" />
                        </button>
                    )}
                </div>

                <div className="flex bg-white rounded-xl shadow-sm border border-gray-100 p-1 w-full sm:w-auto">
                    {(['all', 'low_stock', 'sale'] as const).map(mode => (
                        <button
                            key={mode}
                            onClick={() => setFilterMode(mode)}
                            className={`flex-1 sm:flex-none px-4 py-2 text-sm font-semibold rounded-lg transition-all ${filterMode === mode ? 'bg-gray-900 text-white shadow-sm' : 'text-gray-500 hover:text-gray-900 hover:bg-gray-50'}`}
                        >
                            {mode === 'all' ? 'All Products' : mode === 'low_stock' ? 'Low Stock' : 'Sale Items'}
                        </button>
                    ))}
                </div>
            </div>

            {/* Product Table / Empty */}
            {filteredProducts.length === 0 ? (
                <div className="bg-white rounded-2xl border border-dashed border-gray-200 p-16 text-center">
                    <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center mx-auto mb-4">
                        <PackageSearch className="w-7 h-7 text-blue-500" />
                    </div>
                    <h3 className="text-base font-bold text-gray-900 mb-1">{search ? 'No results found' : 'No products yet'}</h3>
                    <p className="text-sm text-gray-400 max-w-xs mx-auto">
                        {search ? `No product matches "${search}".` : 'Add your first product to start selling.'}
                    </p>
                    {!search && (
