import { createCustomerServerClient } from '@/utils/supabase/customer-server';
import { notFound, redirect } from 'next/navigation';
import { MapPin, Phone, Mail, FileText, Truck } from 'lucide-react';
import Link from 'next/link';
import PrintButton from './PrintButton';
import { formatPriceWithUnit, formatQuantityLabel } from '@/lib/products';
import { hasShopCustomerLink } from '@/lib/auth/context';

export const revalidate = 0;

interface ShopInvoiceView {
    id: string;
    shop_name: string;
    logo_url: string | null;
    company_address: string | null;
    invoice_notes: string | null;
    tax_rate: number | null;
    primary_color: string | null;
    route_path: string;
}

interface InvoiceOrderItem {
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    ordered_quantity: number | null;
    ordered_unit: string | null;
    selling_unit_value: number | null;
    selling_unit: string | null;
    products: {
        title: string | null;
        image_urls: string[] | null;
    } | null;
}

interface InvoiceOrder {
    id: string;
    created_at: string;
    status: string;
    total_amount: number | null;
    payment_method: string | null;
    customer_name: string | null;
    customer_email: string | null;
    customer_phone: string | null;
    customer_address: string | null;
    customer_city: string | null;
    customer_postal: string | null;
    tracking_number: string | null;
    tracking_carrier: string | null;
    tracking_url: string | null;
    order_items: InvoiceOrderItem[];
}

export default async function InvoicePage({ params }: { params: Promise<{ slug: string; id: string }> }) {
    const { slug, id } = await params;
    const supabase = await createCustomerServerClient();

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
        redirect(`/shop/${slug}/login?next=${encodeURIComponent(`/shop/${slug}/invoice/${id}`)}`);
    }

    // 1. Fetch Shop
    const { data: shop, error: shopError } = await supabase
        .from('shops')
        .select('id, shop_name, logo_url, company_address, invoice_notes, tax_rate, primary_color, route_path')
        .eq('route_path', slug)
        .maybeSingle<ShopInvoiceView>();

    if (shopError || !shop) notFound();

    const isShopCustomer = await hasShopCustomerLink(supabase, {
        shopId: shop.id,
        userId: user.id,
    });

    if (!isShopCustomer) {
        redirect(`/shop/${slug}`);
    }

    // 2. Fetch Order + Items

    const { data: order, error: orderError } = await supabase
        .from('orders')
        .select(`
            *,
            order_items (
                id, product_id, quantity, unit_price, ordered_quantity, ordered_unit, selling_unit_value, selling_unit,
                products ( title, image_urls )
            )
        `)
        .eq('id', id)
        .eq('shop_id', shop.id)
        .eq('customer_auth_id', user.id)
        .maybeSingle<InvoiceOrder>();

    if (orderError || !order) {
        return (
            <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-4">
                <FileText className="w-16 h-16 text-gray-300 mb-4" />
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Invoice Not Found</h1>
                <p className="text-gray-500 mb-6 text-center max-w-sm">This invoice does not exist or has been removed.</p>
                <Link href={`/shop/${slug}`} className="text-blue-600 font-medium hover:underline">Return to Shop</Link>
            </div>
        );
    }

    // Financial Calculations
    const items = order.order_items || [];
    const subtotal = items.reduce((s: number, item: InvoiceOrderItem) => {
        const lineTotal = item.unit_price * item.quantity;
        return s + Number(lineTotal);
    }, 0);
    const taxRate = Number(shop.tax_rate) || 0;
    const taxAmount = subtotal * (taxRate / 100);
    const grandTotal = Number(order.total_amount) || subtotal + taxAmount;

    const invoiceNumber = `INV-${order.id.split('-')[0].toUpperCase()}`;
    const orderDate = new Date(order.created_at).toLocaleDateString('en-GB', {
        year: 'numeric', month: 'long', day: 'numeric'
    });

    const accentColor = shop.primary_color || '#2563EB';

    const STATUS_LABELS: Record<string, { label: string; color: string }> = {
        processing: { label: 'Processing', color: '#F59E0B' },
        packed:     { label: 'Packed', color: '#6366F1' },
        shipped:    { label: 'Shipped', color: '#3B82F6' },
        delivered:  { label: 'Delivered', color: '#10B981' },
        cancelled:  { label: 'Cancelled', color: '#EF4444' },
    };
    const statusInfo = STATUS_LABELS[order.status] || STATUS_LABELS.processing;

    return (
        <div className="min-h-screen bg-slate-100 py-8 px-4 sm:px-6 lg:px-8 font-sans">
            <div className="max-w-4xl mx-auto">

                {/* Action Bar */}
                <div className="mb-6 flex justify-between items-center hide-on-print print:hidden">
                    <Link href={`/shop/${slug}/order/${id}`} className="text-sm font-medium text-gray-600 hover:text-gray-900 flex items-center gap-2 transition">
                        ← Back to Order Tracker
                    </Link>
                    <div className="flex items-center gap-2">
                        <Link
                            href={`/shop/${slug}`}
                            className="text-sm font-medium text-gray-500 hover:text-gray-900 border border-gray-200 bg-white px-4 py-2 rounded-xl transition"
                        >
                            Continue Shopping
                        </Link>
                        <PrintButton />
                    </div>
                </div>

                {/* Invoice Card */}
                <div className="bg-white shadow-2xl rounded-2xl overflow-hidden print:shadow-none print:rounded-none">

                    {/* ── TOP ACCENT BAR ── */}
                    <div style={{ backgroundColor: accentColor }} className="h-2 w-full" />

                    {/* ── HEADER ── */}
                    <div className="px-10 py-8 sm:py-10 flex flex-col sm:flex-row justify-between items-start gap-8 border-b border-gray-100">
                        {/* Shop Identity */}
                        <div>
                            {shop.logo_url ? (
                                <img src={shop.logo_url} alt={shop.shop_name} className="h-14 w-auto object-contain mb-5" />
                            ) : (
                                <div className="flex items-center gap-3 mb-5">
                                    <div style={{ backgroundColor: accentColor }} className="w-11 h-11 rounded-xl flex items-center justify-center text-white font-black text-xl">
                                        {shop.shop_name[0].toUpperCase()}
                                    </div>
                                    <h1 className="text-2xl font-extrabold text-gray-900">{shop.shop_name}</h1>
                                </div>
                            )}
                            {shop.company_address && (
                                <div className="text-sm text-gray-500 flex items-start gap-2">
                                    <MapPin className="w-4 h-4 text-gray-400 mt-0.5 flex-shrink-0" />
                                    <p className="whitespace-pre-line leading-relaxed">{shop.company_address}</p>
                                </div>
                            )}
                        </div>

                        {/* Invoice Meta */}
                        <div className="sm:text-right">
                            <p className="text-5xl font-black tracking-tight" style={{ color: accentColor }}>INVOICE</p>
                            <div className="mt-4 space-y-1.5 text-sm">
                                <div className="flex sm:justify-end items-center gap-2">
                                    <span className="text-gray-400 font-medium">Invoice No.</span>
                                    <span className="font-mono font-bold text-gray-800">{invoiceNumber}</span>
                                </div>
                                <div className="flex sm:justify-end items-center gap-2">
                                    <span className="text-gray-400 font-medium">Date</span>
                                    <span className="font-semibold text-gray-700">{orderDate}</span>
                                </div>
                                <div className="flex sm:justify-end items-center gap-2">
                                    <span className="text-gray-400 font-medium">Status</span>
                                    <span className="px-2.5 py-0.5 rounded-full text-xs font-bold text-white" style={{ backgroundColor: statusInfo.color }}>
                                        {statusInfo.label}
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* ── BILL TO / SHIP TO ── */}
                    <div className="px-10 py-6 grid grid-cols-1 sm:grid-cols-2 gap-6 bg-gray-50/50 border-b border-gray-100">
                        <div>
                            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Bill To</p>
                            <p className="font-bold text-gray-900">{order.customer_name || '—'}</p>
                            <div className="mt-1.5 space-y-1 text-sm text-gray-500">
                                {order.customer_email && (
                                    <p className="flex items-center gap-2"><Mail className="w-3.5 h-3.5 text-gray-400" /> {order.customer_email}</p>
                                )}
                                {order.customer_phone && (
                                    <p className="flex items-center gap-2"><Phone className="w-3.5 h-3.5 text-gray-400" /> {order.customer_phone}</p>
                                )}
                            </div>
                        </div>
                        <div>
                            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Ship To</p>
                            {order.customer_address ? (
                                <div className="text-sm text-gray-600 space-y-0.5">
                                    <p className="font-semibold text-gray-800">{order.customer_name}</p>
                                    <p>{order.customer_address}</p>
                                    {order.customer_city && <p>{order.customer_city}{order.customer_postal ? ` — ${order.customer_postal}` : ''}</p>}
                                </div>
                            ) : (
                                <p className="text-sm text-gray-400 italic">No address on file</p>
                            )}
                        </div>
                    </div>

                    {/* ── TRACKING INFO (if available) ── */}
                    {order.tracking_number && (
                        <div className="px-10 py-4 border-b border-gray-100 bg-blue-50/40 flex flex-wrap items-center gap-4">
                            <Truck className="w-5 h-5 text-blue-500 flex-shrink-0" />
                            <div className="flex items-center gap-3 flex-wrap text-sm">
                                <span className="font-semibold text-gray-600">Tracking:</span>
                                <span className="font-mono font-bold text-blue-700 bg-blue-100/70 px-2 py-0.5 rounded">
                                    {order.tracking_carrier && `${order.tracking_carrier} — `}{order.tracking_number}
                                </span>
                                {order.tracking_url && (
                                    <a href={order.tracking_url} target="_blank" rel="noopener noreferrer"
                                        className="text-blue-600 underline text-xs font-semibold hover:text-blue-800 transition">
                                        Track Shipment →
                                    </a>
                                )}
                            </div>
                        </div>
                    )}

                    {/* ── LINE ITEMS ── */}
                    <div className="px-10 py-8">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr style={{ borderBottomColor: accentColor }} className="border-b-2">
                                    <th className="pb-3 text-xs uppercase tracking-widest text-gray-400 font-semibold">Description</th>
                                    <th className="pb-3 text-xs uppercase tracking-widest text-gray-400 font-semibold text-center w-20">Qty</th>
                                    <th className="pb-3 text-xs uppercase tracking-widest text-gray-400 font-semibold text-right w-32">Unit Price</th>
                                    <th className="pb-3 text-xs uppercase tracking-widest text-gray-400 font-semibold text-right w-32">Amount</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {items.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="py-8 text-center text-sm text-gray-400 italic">No line items recorded</td>
                                    </tr>
                                ) : items.map((item: InvoiceOrderItem) => {
                                    const lineTotal = item.unit_price * item.quantity;
                                    return (
                                        <tr key={item.id} className="text-gray-700 hover:bg-gray-50/50 transition-colors">
                                            <td className="py-4 pr-4">
                                                <div className="flex items-center gap-3">
                                                    {item.products?.image_urls?.[0] && (
                                                        <img
                                                            src={item.products.image_urls[0]}
                                                            alt={item.products?.title || 'Product'}
                                                            className="w-10 h-10 rounded-lg object-cover border border-gray-100 print:hidden"
                                                        />
                                                    )}
                                                    <p className="font-semibold text-gray-900">{item.products?.title || 'Product'}</p>
                                                    <p className="text-xs text-gray-400">
                                                        {formatQuantityLabel(item.ordered_quantity ?? item.quantity, item.ordered_unit ?? item.selling_unit ?? 'item')}
                                                    </p>
                                                </div>
                                            </td>
                                            <td className="py-4 text-center font-mono text-gray-500">x{item.quantity}</td>
                                            <td className="py-4 text-right font-mono text-gray-500">
                                                {formatPriceWithUnit(item.unit_price, item.selling_unit ?? item.ordered_unit ?? 'item', item.selling_unit_value ?? 1)}
                                            </td>
                                            <td className="py-4 text-right font-mono font-bold text-gray-900">Rs. {Number(lineTotal).toFixed(2)}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>

                        {/* Totals */}
                        <div className="mt-8 flex justify-end">
                            <div className="w-full sm:w-72 space-y-2 text-sm">
                                <div className="flex justify-between text-gray-500 py-1.5">
                                    <span>Subtotal</span>
                                    <span className="font-mono">Rs. {subtotal.toFixed(2)}</span>
                                </div>
                                {taxRate > 0 && (
                                    <div className="flex justify-between text-gray-500 py-1.5">
                                        <span>Tax ({taxRate}%)</span>
                                        <span className="font-mono">Rs. {taxAmount.toFixed(2)}</span>
                                    </div>
                                )}
                                {order.payment_method && (
                                    <div className="flex justify-between text-gray-400 py-1.5">
                                        <span>Payment</span>
                                        <span className="capitalize">{order.payment_method === 'cod' ? 'Cash on Delivery' : 'Online Payment'}</span>
                                    </div>
                                )}
                                <div className="flex justify-between items-center py-4 border-t-2" style={{ borderColor: accentColor }}>
                                    <span className="text-lg font-extrabold text-gray-900">Total</span>
                                    <span className="font-black text-xl font-mono" style={{ color: accentColor }}>Rs. {grandTotal.toFixed(2)}</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* ── FOOTER ── */}
                    <div className="px-10 py-8 bg-gray-50 border-t border-gray-100">
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 text-sm">
                            {shop.invoice_notes && (
                                <div>
                                    <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Notes & Terms</p>
                                    <p className="text-gray-500 whitespace-pre-line leading-relaxed">{shop.invoice_notes}</p>
                                </div>
                            )}
                            <div>
                                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Order Tracker</p>
                                <p className="text-gray-500 text-xs leading-relaxed mb-2">
                                    Track the live status of your order at any time:
                                </p>
                                <a
                                    href={`/shop/${slug}/order/${id}`}
                                    className="text-xs font-mono underline break-all"
                                    style={{ color: accentColor }}
                                >
                                    {`/shop/${slug}/order/${id}`}
                                </a>
                            </div>
                        </div>

                        {/* Payment Status strip */}
                        <div className="mt-8 pt-6 border-t border-gray-200 flex items-center justify-between flex-wrap gap-4">
                            <p className="text-xs text-gray-400">
                                Thank you for ordering from <span className="font-bold text-gray-600">{shop.shop_name}</span>.
                            </p>
                            <p className="text-xs text-gray-300">Powered by MyShop Platform • Auto-generated invoice</p>
                        </div>
                    </div>

                    {/* ── BOTTOM ACCENT BAR ── */}
                    <div style={{ backgroundColor: accentColor }} className="h-1.5 w-full opacity-40" />
                </div>
            </div>

            {/* Print Styles */}
            <style dangerouslySetInnerHTML={{ __html: `
                @media print {
                    body { background-color: white !important; margin: 0; }
                    .print\\:hidden { display: none !important; }
                    * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
                    @page { margin: 10mm; }
                }
            ` }} />
        </div>
    );
}

'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import Link from 'next/link';
import { createCustomerClient } from '@/utils/supabase/customer-client';
import { Package, Truck, CheckCircle, Store, Receipt, Clock, Box, MapPin, Mail, Phone, AlertCircle, RefreshCw, ExternalLink } from 'lucide-react';
import { formatPriceWithUnit, formatQuantityLabel } from '@/lib/products';

interface ShopData {
    id: string;
    shop_name: string;
    logo_url?: string | null;
    primary_color?: string | null;
}

interface OrderItem {
    quantity: number;
    unit_price: number;
    ordered_quantity?: number | null;
    ordered_unit?: string | null;
    selling_unit?: string | null;
    selling_unit_value?: number | null;
    products?: {
        title?: string | null;
        image_urls?: string[] | null;
    } | null;
}

interface OrderData {
    id: string;
    status: string;
    created_at: string;
    total_amount: number;
    packed_at?: string;
    shipped_at?: string;
    delivered_at?: string;
    tracking_number?: string | null;
    tracking_carrier?: string | null;
    tracking_url?: string | null;
    customer_name?: string | null;
    customer_email?: string | null;
    customer_phone?: string | null;
    customer_address?: string | null;
    customer_city?: string | null;
    customer_postal?: string | null;
    order_items?: OrderItem[];
}

const STEPS = [
    { id: 'processing', label: 'Processing', sub: 'Order received, being prepared', Icon: Clock },
    { id: 'packed',     label: 'Packed',     sub: 'Packed and ready to ship', Icon: Box },
    { id: 'shipped',    label: 'Shipped',    sub: 'On the way to you', Icon: Truck },
    { id: 'delivered',  label: 'Delivered',  sub: 'Successfully delivered', Icon: CheckCircle },
];

const STATUS_COLOR: Record<string, { ring: string; bg: string; text: string }> = {
    processing: { ring: 'ring-amber-400',  bg: 'bg-amber-500',   text: 'text-amber-600' },
    packed:     { ring: 'ring-violet-400', bg: 'bg-violet-500',  text: 'text-violet-600' },
    shipped:    { ring: 'ring-blue-400',   bg: 'bg-blue-500',    text: 'text-blue-600' },
    delivered:  { ring: 'ring-emerald-400',bg: 'bg-emerald-500', text: 'text-emerald-600' },
    cancelled:  { ring: 'ring-red-400',    bg: 'bg-red-500',     text: 'text-red-600' },
};

export default function OrderTrackerPage({ params }: { params: Promise<{ slug: string; id: string }> }) {
    const supabase = createCustomerClient();
    const [order, setOrder] = useState<OrderData | null>(null);
    const [shop, setShop] = useState<ShopData | null>(null);
    const [loading, setLoading] = useState(true);
    const [slug, setSlug] = useState('');
    const [orderId, setOrderId] = useState('');
    const [lastRefreshed, setLastRefreshed] = useState<Date>(new Date());
    const [refreshing, setRefreshing] = useState(false);
    const pollRef = useRef<ReturnType<typeof setInterval> | null>(null);

    const load = useCallback(async (s: string, id: string, isRefresh = false) => {
        if (isRefresh) setRefreshing(true);

        const { data: { user } } = await supabase.auth.getUser();
        if (!user) {
            window.location.href = `/shop/${s}/login?next=${encodeURIComponent(`/shop/${s}/order/${id}`)}`;
            return;
        }

        const { data: shopData } = await supabase
            .from('shops')
            .select('*, primary_color')
            .eq('route_path', s)
            .single<ShopData>();
        if (!shopData) { setLoading(false); return; }
        setShop(shopData);

        const { data: shopCustomer } = await supabase
            .from('shop_customers')
            .select('id')
            .eq('shop_id', shopData.id)
            .eq('auth_user_id', user.id)
            .maybeSingle<{ id: string }>();

        if (!shopCustomer?.id) {
            window.location.href = `/shop/${s}`;
            return;
        }

        const { data: orderData } = await supabase
            .from('orders')
            .select(`*, order_items(quantity, unit_price, ordered_quantity, ordered_unit, selling_unit_value, selling_unit, products(title, image_urls))`)
            .eq('id', id)
            .eq('shop_id', shopData.id)
            .eq('customer_auth_id', user.id)
            .single<OrderData>();

        setOrder(orderData);
        setLastRefreshed(new Date());
        setLoading(false);
        if (isRefresh) setRefreshing(false);
    }, [supabase]);

    useEffect(() => {
        params.then(({ slug, id }) => {
            setSlug(slug);
            setOrderId(id);
            load(slug, id);
        });
    }, [params, load]);

    // Auto-poll every 30 seconds
    useEffect(() => {
        if (!slug || !orderId) return;
        pollRef.current = setInterval(() => load(slug, orderId, true), 30000);
        return () => { if (pollRef.current) clearInterval(pollRef.current); };
    }, [slug, orderId, load]);

    if (loading) {
        return (
            <div className="min-h-screen bg-slate-50 flex items-center justify-center">
                <div className="text-center">
                    <div className="w-10 h-10 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4" />
                    <p className="text-gray-500 text-sm font-medium">Loading your order...</p>
                </div>
            </div>
        );
    }

    if (!shop) {
        return <div className="min-h-screen flex items-center justify-center text-gray-600">Shop not found.</div>;
    }

    const accent = shop.primary_color || '#2563EB';

    if (!order) {
        return (
            <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
                <AlertCircle className="w-16 h-16 text-gray-300 mb-4" />
                <h1 className="text-2xl font-bold text-gray-900 mb-2">Order Not Found</h1>
                <p className="text-gray-500 max-w-sm mb-6">We couldn&apos;t find tracking info for this order.</p>
                <Link href={`/shop/${slug}`} className="text-blue-600 font-medium hover:underline">Return to {shop.shop_name}</Link>
            </div>
        );
    }

    const isCancelled = order.status === 'cancelled';
    const stepIndex = STEPS.findIndex(s => s.id === order.status);
    const progress = isCancelled ? 0 : Math.max(0, (stepIndex / (STEPS.length - 1)) * 100);
    const colors = STATUS_COLOR[order.status] || STATUS_COLOR.processing;

    const items = order.order_items || [];

    const statusTimestamps: Record<string, string | undefined> = {
        processing: order.created_at,
        packed:     order.packed_at,
        shipped:    order.shipped_at,
        delivered:  order.delivered_at,
    };

    return (
        <div className="min-h-screen bg-slate-50 font-sans">

            {/* ── TOP NAV ── */}
            <nav className="bg-white border-b border-gray-100 sticky top-0 z-40 shadow-sm">
                <div className="max-w-4xl mx-auto px-4 sm:px-6 py-3 flex items-center justify-between">
                    <Link href={`/shop/${slug}`} className="flex items-center gap-2 text-sm font-semibold text-gray-700 hover:text-gray-900 transition">
                        {shop.logo_url ? (
                            <img src={shop.logo_url} alt={shop.shop_name} className="h-7 w-auto object-contain" />
                        ) : (
                            <div style={{ backgroundColor: accent }} className="w-7 h-7 rounded-lg flex items-center justify-center text-white font-black text-sm">
                                {shop.shop_name[0]}
                            </div>
                        )}
                        <span>{shop.shop_name}</span>
                    </Link>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={() => load(slug, orderId, true)}
                            className="flex items-center gap-1.5 text-xs text-gray-400 hover:text-gray-600 transition"
                            disabled={refreshing}
                        >
                            <RefreshCw className={`w-3.5 h-3.5 ${refreshing ? 'animate-spin' : ''}`} />
                            <span className="hidden sm:inline">Auto-refresh</span>
                        </button>
                        <Link
                            href={`/shop/${slug}/invoice/${orderId}`}
                            className="flex items-center gap-1.5 text-sm font-semibold border rounded-xl px-3 py-1.5 transition"
                            style={{ borderColor: accent, color: accent }}
                        >
                            <Receipt className="w-4 h-4" />
                            <span className="hidden sm:inline">Invoice</span>
                        </Link>
                    </div>
                </div>
            </nav>

            <div className="max-w-4xl mx-auto px-4 sm:px-6 py-8 space-y-6">

                {/* ── ORDER HERO ── */}
                <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
                    {/* Accent top */}
                    <div style={{ backgroundColor: accent }} className="h-1.5 w-full" />

                    <div className="p-8 sm:p-10 text-center">
                        <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-1">Order Reference</p>
                        <h1 className="text-4xl font-black text-gray-900 mb-1">#{order.id.split('-')[0].toUpperCase()}</h1>
                        <p className="text-sm text-gray-400">
                            Placed on {new Date(order.created_at).toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}
                        </p>

                        {isCancelled && (
                            <div className="mt-6 inline-flex items-center gap-2 bg-red-50 text-red-700 border border-red-100 px-5 py-3 rounded-2xl font-bold text-sm">
                                <AlertCircle className="w-4 h-4" /> This order has been cancelled
                            </div>
                        )}

                        {!isCancelled && (
                            <>
                                {/* ── PROGRESS BAR ── */}
                                <div className="mt-12 mb-4 relative px-4">
                                    {/* Track */}
                                    <div className="absolute top-7 left-[calc(12%+1rem)] right-[calc(12%+1rem)] h-1.5 bg-gray-100 rounded-full overflow-hidden">
                                        <div
                                            className="h-full rounded-full transition-all duration-1000 ease-in-out"
                                            style={{ width: `${progress}%`, backgroundColor: accent }}
                                        />
                                    </div>

                                    {/* Steps */}
                                    <div className="relative flex justify-between">
                                        {STEPS.map((step, i) => {
                                            const done = !isCancelled && i < stepIndex;
                                            const current = i === stepIndex && !isCancelled;
                                            const pending = i > stepIndex;
                                            const Icon = step.Icon;
                                            const ts = statusTimestamps[step.id];

                                            return (
                                                <div key={step.id} className="flex flex-col items-center flex-1">
                                                    <div
                                                        className={`
                                                            w-14 h-14 rounded-full flex items-center justify-center border-4 transition-all duration-500 shadow-sm
                                                            ${current ? `ring-4 ring-offset-2 scale-110 ${colors.ring}` : ''}
                                                            ${done ? 'border-transparent text-white' : 'border-gray-200 bg-white'}
                                                            ${pending ? 'text-gray-300' : ''}
                                                        `}
                                                        style={done || current ? { backgroundColor: accent, borderColor: accent, color: '#fff' } : {}}
                                                    >
                                                        <Icon className={`w-6 h-6 ${current ? 'animate-pulse' : ''}`} />
                                                    </div>
                                                    <p className={`mt-3 text-sm font-bold ${pending ? 'text-gray-300' : 'text-gray-700'}`}>{step.label}</p>
                                                    {ts && !pending && (
                                                        <p className="text-[10px] text-gray-400 mt-0.5">
                                                            {new Date(ts).toLocaleDateString('en-GB', { day: 'numeric', month: 'short' })}
                                                        </p>
                                                    )}
                                                </div>
                                            );
                                        })}
