                                    className="mb-8 max-w-lg leading-relaxed"
                                >
                                    {shop.tagline}
                                </p>
                            )}
                            {(isHeroFull || isBoldLayout) && (
                                <button
                                    onClick={onOpenCart}
                                    style={{
                                        background: c.button_style === 'outline'
                                            ? 'transparent'
                                            : c.button_style === 'soft'
                                                ? `rgba(${accentRgb},0.15)`
