                            {!sessionUser && (
                                <>
                                    <a href={`/shop/${shop.route_path}/login`} className="hidden sm:flex items-center text-sm font-medium text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-lg hover:bg-gray-50 transition">
