                        </div>
                        {rest.length > 0 && <a href="#all" style={{ color: primaryColor }} className="text-sm font-semibold hover:opacity-70 transition">View All →</a>}
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
                        {featured.map((product, i) => (
                            <div
                                key={product.id}
                                onClick={() => onAddToCart?.(product)}
                                className={`group cursor-pointer relative rounded-2xl overflow-hidden border border-white/[0.06] hover:border-white/20 transition-all duration-300 ${i === 0 ? 'sm:row-span-1' : ''}`}
                            >
                                <div className="aspect-square bg-white/5 relative overflow-hidden">
                                    {product.image_urls?.[0] ? (
                                        <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 opacity-80 group-hover:opacity-100" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <ShoppingBag className="w-12 h-12 text-white/10" strokeWidth={1} />
                                        </div>
                                    )}
                                    <div className="absolute inset-0 bg-gradient-to-t from-[#080810] via-transparent to-transparent" />
                                    {product.stock_quantity === 0 && (
                                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                                            <span className="text-xs font-bold text-white/40 uppercase tracking-widest">Sold Out</span>
                                        </div>
                                    )}
                                </div>
                                <div className="p-4">
                                    <p className="font-bold text-white text-sm mb-0.5 truncate">{product.title}</p>
                                    {product.description && <p className="text-xs text-white/30 line-clamp-1 mb-3">{product.description}</p>}
                                    <div className="flex items-center justify-between">
                                        <span style={{ color: primaryColor }} className="text-base font-extrabold">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                            disabled={product.stock_quantity === 0}
                                            style={{ backgroundColor: product.stock_quantity > 0 ? primaryColor : undefined }}
                                            className={`text-xs font-bold px-3 py-1.5 rounded-lg transition ${product.stock_quantity > 0 ? 'text-white hover:opacity-85' : 'bg-white/5 text-white/20 cursor-not-allowed'}`}
                                        >
                                            {product.stock_quantity > 0 ? '+ Add' : 'Sold'}
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {/* Promo Banner */}
            {rest.length > 0 && (
                <section className="max-w-7xl mx-auto px-5 lg:px-10 mb-4">
                    <div className="rounded-3xl overflow-hidden relative" style={{ background: `linear-gradient(135deg, ${primaryColor}88, ${primaryColor}33)` }}>
                        <div className="absolute inset-0 border border-white/10 rounded-3xl" />
                        <div className="relative px-8 py-10 flex flex-col md:flex-row items-center justify-between gap-6">
                            <div>
                                <p className="text-white/50 text-xs uppercase tracking-widest mb-2">More To Discover</p>
                                <h3 className="text-xl font-extrabold text-white">{rest.length} More Products Await</h3>
                            </div>
                            <a href="#all" className="bg-white text-sm font-bold px-7 py-3.5 rounded-xl hover:bg-white/90 transition" style={{ color: primaryColor }}>
                                Browse Catalogue →
                            </a>
                        </div>
                    </div>
                </section>
            )}

            {saleItems.length > 0 && (
                <section className="max-w-7xl mx-auto px-6 py-12">
                    <div className="flex items-center justify-between mb-8">
                        <div className="flex items-center gap-3">
                            <h2 className="text-3xl font-light text-white tracking-wide">Deals</h2>
                            <span className="bg-indigo-500 text-white text-[10px] font-bold uppercase px-2 py-0.5 mt-1 animate-pulse">Ends Soon</span>
                        </div>
                        <div className="h-[1px] flex-1 bg-zinc-800 ml-8"></div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                        {saleItems.map((product) => (
                            <div key={product.id} onClick={() => onAddToCart?.(product)} className="group cursor-pointer bg-zinc-900 border border-indigo-900/40 hover:border-indigo-500/50 transition-all duration-500 rounded-none relative">
                                <div className="aspect-[4/5] bg-zinc-800 relative overflow-hidden">
                                    {product.image_urls?.[0] ? (
                                        <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 opacity-90 group-hover:opacity-100" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <ShoppingBag className="w-12 h-12 text-zinc-700" strokeWidth={1} />
                                        </div>
                                    )}
                                    {product.stock_quantity === 0 ? (
                                        <div className="absolute inset-0 bg-zinc-950/80 flex items-center justify-center backdrop-blur-sm">
                                            <span className="text-xs font-medium text-zinc-400 uppercase tracking-[0.2em] border border-zinc-700 px-4 py-2">Sold Out</span>
                                        </div>
                                    ) : (
                                        <>
                                            {product.stock_quantity > 0 && product.stock_quantity <= 5 && (
                                                <span className="absolute top-3 right-3 bg-red-600 text-white text-[10px] font-bold px-2 py-1 uppercase tracking-widest">Last {product.stock_quantity}</span>
                                            )}
                                            {product.compare_at_price != null && product.compare_at_price > product.price && product.stock_quantity > 0 && (
                                                <span className="absolute top-3 left-3 bg-indigo-500 text-white text-[10px] font-bold px-2 py-1 uppercase tracking-widest animate-pulse">Sale</span>
                                            )}
                                        </>
                                    )}
                                </div>
                                <div className="p-5">
                                    <h3 className="font-medium text-white tracking-wide text-lg mb-1 truncate">{product.title}</h3>
                                    {product.description && <p className="text-sm text-zinc-500 line-clamp-1 mb-4">{product.description}</p>}
                                    <div className="flex flex-col gap-3 mt-3">
                                        <div className="flex items-center gap-2">
                                            <span style={{ color: primaryColor }} className="text-lg font-bold">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                            {product.compare_at_price != null && product.compare_at_price > product.price && (
                                                <span className="text-xs text-zinc-600 line-through">Rs. {product.compare_at_price.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                            )}
                                        </div>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                            disabled={product.stock_quantity === 0}
                                            className={`text-[10px] tracking-widest uppercase font-bold w-full py-2.5 transition-all ${product.stock_quantity > 0 ? 'bg-indigo-500 hover:bg-indigo-600 text-white shadow-[0_0_15px_rgba(99,102,241,0.3)]' : 'bg-zinc-800 text-zinc-500 cursor-not-allowed'}`}
                                        >
                                            {product.stock_quantity > 0 ? 'Claim Deal' : 'Sold'}
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {/* All Products */}
            {rest.length > 0 && (
                <section id="all" className="max-w-7xl mx-auto px-5 lg:px-10 py-16">
                    <h2 className="text-2xl font-extrabold text-white mb-8">All Products</h2>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
                        {rest.map((product) => (
                            <div key={product.id} onClick={() => onAddToCart?.(product)} className="group cursor-pointer bg-white/[0.03] border border-white/[0.06] rounded-2xl overflow-hidden hover:border-white/15 transition-all duration-300">
                                <div className="aspect-square bg-white/5 overflow-hidden relative">
                                    {product.image_urls?.[0] ? (
                                        <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500 opacity-80 group-hover:opacity-100" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <ShoppingBag className="w-8 h-8 text-white/10" strokeWidth={1} />
                                        </div>
                                    )}
                                    {product.stock_quantity === 0 && (
                                        <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                                            <span className="text-xs text-white/30 uppercase tracking-widest">Sold Out</span>
                                        </div>
                                    )}
                                </div>
                                <div className="p-4">
                                    <p className="font-bold text-white text-sm truncate mb-2">{product.title}</p>
                                    <div className="flex items-center justify-between">
                                        <span style={{ color: primaryColor }} className="text-sm font-extrabold">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                            disabled={product.stock_quantity === 0}
                                            style={{ backgroundColor: product.stock_quantity > 0 ? primaryColor : undefined }}
                                            className={`text-xs font-bold px-3 py-1.5 rounded-lg transition ${product.stock_quantity > 0 ? 'text-white hover:opacity-85' : 'bg-white/5 text-white/20 cursor-not-allowed'}`}
                                        >
                                            + Add
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {products.length === 0 && (
                <section className="max-w-7xl mx-auto px-5 lg:px-10 py-24 text-center">
                    <PackageOpen className="w-16 h-16 text-white/10 mx-auto mb-4" strokeWidth={1} />
                    <p className="text-white/20 font-medium">No products yet. Check back soon!</p>
                </section>
            )}

            {/* Footer */}
            <footer className="border-t border-white/[0.05] py-10 mt-8">
                <div className="max-w-7xl mx-auto px-5 lg:px-10 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <span className="text-sm font-bold text-white/30">{shop.shop_name}</span>
                    <p className="text-xs text-white/15">{shop.footer_text || `© ${new Date().getFullYear()} ${shop.shop_name}. All rights reserved.`}</p>
                    <p className="text-xs text-white/10">Powered by <span style={{ color: primaryColor }} className="font-bold">MyShop</span></p>
                </div>
            </footer>
        </div>
    );
}

import React from 'react';
import { PackageOpen, ShoppingBag, ShieldCheck, Truck, Sparkles, Star } from 'lucide-react';
import { formatPriceWithUnit, type ProductUnit } from '@/lib/products';

interface Product {
    id: string;
    title: string;
    description: string | null;
    price: number;
    selling_unit_value: number;
    selling_unit: ProductUnit;
    stock_quantity: number;
    image_urls: string[] | null;
    compare_at_price?: number | null;
}

interface ShopConfig {
    shop_name: string;
    route_path: string;
    tagline: string | null;
    primary_color: string;
    font: string;
    banner_url: string | null;
    logo_url: string | null;
    announcement_bar: string | null;
    footer_text: string | null;
}

interface Props {
    shop: ShopConfig;
    products: Product[];
    onAddToCart?: (product: Product) => void;
    cartCount?: number;
    onOpenCart?: () => void;
    sessionUser?: unknown;
    customerDisplayName?: string;
    onLogout?: () => void | Promise<void>;
}

export default function VibrantMarket({ shop, products, onAddToCart, cartCount = 0, onOpenCart, sessionUser, customerDisplayName, onLogout }: Props) {
    const primaryColor = shop.primary_color || '#F59E0B';
    const saleItems = products.filter(p => p.compare_at_price != null && p.compare_at_price > p.price);
    const saleFeatured = saleItems.slice(0, 4);
    // Don't show sale items in the standard featured list to avoid duplication on homepage
    const nonSaleProducts = products.filter(p => p.compare_at_price == null || p.compare_at_price <= p.price);
    const featured = nonSaleProducts.slice(0, 4);
    const rest = nonSaleProducts.slice(4);

    return (
        <div style={{ fontFamily: `'${shop.font}', sans-serif` }} className="min-h-screen bg-white text-gray-900">
            {/* Announcement Bar */}
            {shop.announcement_bar && (
                <div style={{ backgroundColor: primaryColor }} className="text-white text-center text-xs py-2.5 px-4 font-bold tracking-wide flex items-center justify-center gap-2">
                    <Sparkles className="w-3.5 h-3.5" />
                    {shop.announcement_bar}
                    <Sparkles className="w-3.5 h-3.5" />
                </div>
            )}

            {/* Navigation */}
            <header className="border-b-2 border-opacity-10 sticky top-0 z-20 bg-white/97 backdrop-blur-sm shadow-sm" style={{ borderColor: `${primaryColor}30` }}>
                <div className="max-w-7xl mx-auto px-5 lg:px-10">
                    <div className="h-16 flex items-center justify-between gap-4">
                        <div className="flex items-center gap-3 flex-shrink-0">
                            {shop.logo_url ? (
                                <img src={shop.logo_url} alt={shop.shop_name} className="h-9 w-auto object-contain" />
                            ) : (
                                <div style={{ backgroundColor: primaryColor }} className="w-10 h-10 rounded-2xl flex items-center justify-center text-white font-extrabold text-lg">
                                    {shop.shop_name[0]}
                                </div>
                            )}
                            <span style={{ color: primaryColor }} className="text-xl font-extrabold tracking-tight">{shop.shop_name}</span>
                        </div>
                        <nav className="hidden md:flex items-center gap-8 text-sm text-gray-500 font-bold">
                            <a href="#products" className="hover:text-gray-900 transition-colors">Shop</a>
                            <a href="#features" className="hover:text-gray-900 transition-colors">About</a>
                        </nav>
                        <div className="flex items-center gap-2">
                            {!sessionUser && (
                                <>
                                    <a href={`/shop/${shop.route_path}/login`} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                        Login
                                    </a>
                                    <a href={`/shop/${shop.route_path}/signup`} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                        Signup
                                    </a>
                                </>
                            )}
                            {sessionUser ? (
                                <a href={`/shop/${shop.route_path}/orders`} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                    {customerDisplayName || 'Account'}
                                </a>
                            ) : (
                                <a href={`/shop/${shop.route_path}/login?next=${encodeURIComponent(`/shop/${shop.route_path}/orders`)}`} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                    My Orders
                                </a>
                            )}
                            {Boolean(sessionUser) && (
                                <>
                                    <a href={`/shop/${shop.route_path}/orders`} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-gray-900 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                        My Orders
                                    </a>
                                    <button onClick={onLogout} className="hidden sm:flex items-center text-sm font-bold text-gray-500 hover:text-red-500 px-3 py-1.5 rounded-xl hover:bg-gray-50 transition">
                                        Logout
                                    </button>
                                </>
                            )}
                            <button
                                onClick={onOpenCart}
                                style={{ backgroundColor: primaryColor, boxShadow: `0 4px 14px ${primaryColor}40` }}
                                className="relative text-white text-sm px-4 py-2 rounded-2xl font-extrabold hover:opacity-90 transition flex items-center gap-2 shadow-lg"
                            >
                                <ShoppingBag className="w-4 h-4" />
                                <span className="hidden sm:inline">Cart</span>
                                {cartCount > 0 && (
                                    <span className="absolute -top-1.5 -right-1.5 bg-red-500 text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center">{cartCount}</span>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            </header>

            {/* Hero */}
            <section
                className="relative overflow-hidden"
                style={{
                    background: shop.banner_url
                        ? `url(${shop.banner_url}) center/cover`
                        : `linear-gradient(135deg, ${primaryColor}22 0%, ${primaryColor}08 60%, white 100%)`
                }}
            >
                {shop.banner_url && <div className="absolute inset-0 bg-white/80" />}
                <div className="relative z-10 max-w-7xl mx-auto px-5 lg:px-10 py-24 md:py-36">
                    <div className="max-w-xl">
                        <div style={{ backgroundColor: `${primaryColor}18`, color: primaryColor }} className="inline-flex items-center gap-1.5 text-xs font-extrabold uppercase tracking-widest px-3 py-1.5 rounded-full mb-5">
                            <Star className="w-3 h-3 fill-current" />
                            {shop.tagline || 'Best Deals!'}
                        </div>
                        <h1 className="text-5xl md:text-6xl font-extrabold tracking-tight text-gray-900 leading-none mb-5">
                            Shop Smart,<br />
                            <span style={{ color: primaryColor }}>Live Better.</span>
                        </h1>
                        <p className="text-gray-500 text-lg mb-8 leading-relaxed">
                            Discover amazing deals on premium products, delivered fast across Sri Lanka.
                        </p>
                        <div className="flex items-center gap-3">
                            <a
                                href="#products"
                                style={{ backgroundColor: primaryColor }}
                                className="inline-flex items-center gap-2 text-white px-7 py-3.5 rounded-2xl font-extrabold hover:opacity-90 transition text-sm shadow-xl"
                            >
                                <ShoppingBag className="w-4 h-4" />
                                Shop Now
                            </a>
                        </div>
                    </div>
                </div>
            </section>

            {/* Trust Strip */}
            <section className="border-y border-gray-100 bg-gray-50">
                <div className="max-w-7xl mx-auto px-5 lg:px-10 py-5">
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {[
                            { icon: Truck, label: 'Island-wide Delivery' },
                            { icon: ShieldCheck, label: 'Secure Payments' },
                            { icon: Sparkles, label: 'Top Quality' },
                            { icon: Star, label: 'Best Prices' },
                        ].map(t => (
                            <div key={t.label} className="flex items-center gap-2 text-xs text-gray-500 font-bold">
                                <t.icon className="w-4 h-4 flex-shrink-0" style={{ color: primaryColor }} strokeWidth={2} />
                                {t.label}
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Flash Sales */}
            {saleFeatured.length > 0 && (
                <section id="sale" className="max-w-7xl mx-auto px-5 lg:px-10 py-16">
                    <div className="flex items-end justify-between mb-8">
                        <div>
                            <p className="text-xs font-extrabold text-red-500 uppercase tracking-widest mb-1 flex items-center gap-1.5 animate-pulse">
                                <Sparkles className="w-3.5 h-3.5" />
                                Limited Time
                            </p>
                            <h2 className="text-2xl font-extrabold text-gray-900">Flash Sale</h2>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {saleFeatured.map((product) => {
                            const isSale = product.compare_at_price != null && product.compare_at_price > product.price;
                            const discountPercent = isSale ? Math.round(((product.compare_at_price! - product.price) / product.compare_at_price!) * 100) : 0;
                            return (
                                <div key={product.id} onClick={() => onAddToCart?.(product)} className="relative group cursor-pointer bg-white border-2 border-red-100/50 rounded-3xl overflow-hidden hover:shadow-2xl hover:-translate-y-1 transition-all duration-300" onMouseEnter={(e) => e.currentTarget.style.borderColor = '#ef444450'} onMouseLeave={(e) => e.currentTarget.style.borderColor = ''}>
                                    <div className="aspect-square bg-gray-50 relative overflow-hidden">
                                        {/* Sale Badge */}
                                        <div className="absolute top-3 right-3 z-10 bg-red-500 text-white shadow-lg text-xs font-extrabold px-3 py-1.5 rounded-full flex items-center gap-1">
                                            {discountPercent}% OFF
                                        </div>

                                        {product.image_urls?.[0] ? (
                                            <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center">
                                                <ShoppingBag className="w-10 h-10 text-gray-200" strokeWidth={1} />
                                            </div>
                                        )}
                                        {product.stock_quantity === 0 && (
                                            <div className="absolute inset-0 bg-white/75 flex items-center justify-center z-10">
                                                <span className="text-xs font-extrabold text-gray-400 uppercase tracking-widest">Sold Out</span>
                                            </div>
                                        )}
                                        {product.stock_quantity > 0 && product.stock_quantity <= 5 && (
                                            <span className="absolute top-3 left-3 bg-orange-500 text-white z-10 text-xs font-extrabold px-2 py-0.5 rounded-full">🔥 {product.stock_quantity} left</span>
                                        )}
                                    </div>
                                    <div className="p-4 bg-red-50/10">
                                        <p className="font-extrabold text-gray-900 text-sm truncate mb-0.5">{product.title}</p>
                                        {product.description && <p className="text-xs text-gray-400 line-clamp-1 mb-3">{product.description}</p>}
                                        <div className="flex items-center justify-between">
                                            <div>
                                                <span className="text-base font-extrabold text-red-600 space-x-1 block leading-tight">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                                <span className="text-xs font-bold text-gray-400 line-through">Rs. {Number(product.compare_at_price).toLocaleString()}</span>
                                            </div>
                                            <button
                                                onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                                disabled={product.stock_quantity === 0}
                                                className={`text-xs font-extrabold px-3 py-1.5 rounded-xl transition ${product.stock_quantity > 0 ? 'bg-red-500 text-white hover:bg-red-600 shadow-sm shadow-red-500/20' : 'bg-gray-100 text-gray-300 cursor-not-allowed'}`}
                                            >
                                                + Add
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </section>
            )}

            {/* Featured */}
            {featured.length > 0 && (
                <section id="products" className="max-w-7xl mx-auto px-5 lg:px-10 py-16">
                    <div className="flex items-end justify-between mb-8">
                        <div>
                            <p style={{ color: primaryColor }} className="text-xs font-extrabold uppercase tracking-widest mb-1 flex items-center gap-1.5">
                                <Sparkles className="w-3.5 h-3.5" />
                                Hot Picks
                            </p>
                            <h2 className="text-2xl font-extrabold text-gray-900">Featured Products</h2>
                        </div>
                        {rest.length > 0 && <a href="#all" style={{ color: primaryColor }} className="text-sm font-extrabold hover:underline">View All →</a>}
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                        {featured.map((product) => (
                            <div key={product.id} onClick={() => onAddToCart?.(product)} className="group cursor-pointer bg-white border-2 border-gray-100 rounded-3xl overflow-hidden hover:shadow-2xl hover:-translate-y-1 transition-all duration-300" onMouseEnter={(e) => e.currentTarget.style.borderColor = `${primaryColor}40`} onMouseLeave={(e) => e.currentTarget.style.borderColor = ''}>
                                <div className="aspect-square bg-gray-50 relative overflow-hidden">
                                    {product.image_urls?.[0] ? (
                                        <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <ShoppingBag className="w-10 h-10 text-gray-200" strokeWidth={1} />
                                        </div>
                                    )}
                                    {product.stock_quantity === 0 && (
                                        <div className="absolute inset-0 bg-white/75 flex items-center justify-center">
                                            <span className="text-xs font-extrabold text-gray-400 uppercase tracking-widest">Sold Out</span>
                                        </div>
                                    )}
                                    {product.stock_quantity > 0 && product.stock_quantity <= 5 && (
                                        <span className="absolute top-2 left-2 bg-red-500 text-white text-xs font-extrabold px-2 py-0.5 rounded-full">🔥 {product.stock_quantity} left</span>
                                    )}
                                </div>
                                <div className="p-4">
                                    <p className="font-extrabold text-gray-900 text-sm truncate mb-0.5">{product.title}</p>
                                    {product.description && <p className="text-xs text-gray-400 line-clamp-1 mb-3">{product.description}</p>}
                                    <div className="flex items-center justify-between">
                                        <div className="flex flex-col">
                                            <span style={{ color: primaryColor }} className="text-base font-extrabold">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                            {product.compare_at_price != null && product.compare_at_price > product.price && (
                                                <span className="text-xs font-bold text-gray-400 line-through">Rs. {Number(product.compare_at_price).toLocaleString()}</span>
                                            )}
                                        </div>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                            disabled={product.stock_quantity === 0}
                                            style={{ backgroundColor: product.stock_quantity > 0 ? primaryColor : undefined }}
                                            className={`text-xs font-extrabold px-3 py-1.5 rounded-xl transition ${product.stock_quantity > 0 ? 'text-white hover:opacity-85' : 'bg-gray-100 text-gray-300 cursor-not-allowed'}`}
                                        >
                                            + Add
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {/* Promo Banner */}
            {rest.length > 0 && (
                <section className="max-w-7xl mx-auto px-5 lg:px-10 mb-4">
                    <div className="rounded-3xl overflow-hidden" style={{ background: `linear-gradient(120deg, ${primaryColor}, ${primaryColor}cc)` }}>
                        <div className="px-8 py-12 flex flex-col md:flex-row items-center justify-between gap-6">
                            <div>
                                <p className="text-white/70 text-xs uppercase tracking-widest font-extrabold mb-2">More Deals</p>
                                <h3 className="text-2xl font-extrabold text-white">Explore Our Full Shop</h3>
                                <p className="text-white/70 text-sm mt-1">{rest.length} more products waiting!</p>
                            </div>
                            <a href="#all" className="flex-shrink-0 bg-white font-extrabold px-7 py-3.5 rounded-2xl text-sm hover:bg-opacity-90 transition" style={{ color: primaryColor }}>
                                Browse All →
                            </a>
                        </div>
                    </div>
                </section>
            )}

            {/* All Products */}
            {rest.length > 0 && (
                <section id="all" className="max-w-7xl mx-auto px-5 lg:px-10 py-16">
                    <h2 className="text-2xl font-extrabold text-gray-900 mb-8">All Products</h2>
                    <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
                        {rest.map((product) => (
                            <div key={product.id} onClick={() => onAddToCart?.(product)} className="group cursor-pointer bg-white border-2 border-gray-100 rounded-3xl overflow-hidden hover:shadow-lg hover:-translate-y-0.5 transition-all duration-300">
                                <div className="aspect-square bg-gray-50 relative overflow-hidden">
                                    {product.image_urls?.[0] ? (
                                        <img src={product.image_urls[0]} alt={product.title} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center">
                                            <ShoppingBag className="w-8 h-8 text-gray-200" strokeWidth={1} />
                                        </div>
                                    )}
                                    {product.stock_quantity === 0 && (
                                        <div className="absolute inset-0 bg-white/70 flex items-center justify-center">
                                            <span className="text-xs font-extrabold text-gray-400 uppercase tracking-wider">Sold Out</span>
                                        </div>
                                    )}
                                </div>
                                <div className="p-3">
                                    <p className="font-extrabold text-gray-900 text-sm truncate mb-2">{product.title}</p>
                                    <div className="flex items-center justify-between">
                                        <div className="flex flex-col">
                                            <span style={{ color: primaryColor }} className="text-sm font-extrabold">{formatPriceWithUnit(product.price, product.selling_unit, product.selling_unit_value)}</span>
                                            {product.compare_at_price != null && product.compare_at_price > product.price && (
                                                <span className="text-xs font-bold text-gray-400 line-through">Rs. {Number(product.compare_at_price).toLocaleString()}</span>
                                            )}
                                        </div>
                                        <button
                                            onClick={(e) => { e.stopPropagation(); onAddToCart?.(product); }}
                                            disabled={product.stock_quantity === 0}
                                            style={{ backgroundColor: product.stock_quantity > 0 ? primaryColor : undefined }}
                                            className={`text-xs font-extrabold px-3 py-1.5 rounded-xl transition ${product.stock_quantity > 0 ? 'text-white hover:opacity-85' : 'bg-gray-100 text-gray-300 cursor-not-allowed'}`}
                                        >
                                            + Add
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </section>
            )}

            {products.length === 0 && (
                <section className="max-w-7xl mx-auto px-5 lg:px-10 py-24 text-center">
                    <PackageOpen className="w-16 h-16 text-gray-200 mx-auto mb-4" strokeWidth={1} />
                    <p className="text-gray-400 font-bold">No products yet. Check back soon!</p>
                </section>
            )}

            {/* Footer */}
            <footer style={{ backgroundColor: primaryColor }} className="py-10 mt-8">
                <div className="max-w-7xl mx-auto px-5 lg:px-10 flex flex-col sm:flex-row items-center justify-between gap-4">
                    <span className="text-white font-extrabold text-base">{shop.shop_name}</span>
                    <p className="text-white/70 text-xs">{shop.footer_text || `© ${new Date().getFullYear()} ${shop.shop_name}. All rights reserved.`}</p>
                    <p className="text-white/40 text-xs">Powered by <span className="font-extrabold text-white">MyShop</span></p>
                </div>
            </footer>
        </div>
    );
}

import { z } from 'zod';

export const PRODUCT_UNITS = ['item', 'kg', 'g', 'litre', 'ml', 'pack'] as const;

export type ProductUnit = (typeof PRODUCT_UNITS)[number];

const UNIT_LABELS: Record<ProductUnit, string> = {
    item: 'item',
    kg: 'kg',
    g: 'g',
    litre: 'litre',
    ml: 'ml',
    pack: 'pack',
};

export const DEFAULT_PRODUCT_UNIT: ProductUnit = 'item';
export const DEFAULT_UNIT_VALUE = 1;
export const DEFAULT_STOCK_UNIT: ProductUnit = 'item';

type UnitCategory = 'mass' | 'volume' | 'count';

function getUnitCategory(unit: ProductUnit): UnitCategory {
    if (unit === 'kg' || unit === 'g') return 'mass';
    if (unit === 'litre' || unit === 'ml') return 'volume';
    return 'count';
}

function getBaseFactor(unit: ProductUnit): number {
    switch (unit) {
        case 'kg':
            return 1000;
        case 'litre':
            return 1000;
        default:
            return 1;
    }
}

export function canConvertUnits(fromUnit: ProductUnit, toUnit: ProductUnit): boolean {
    return getUnitCategory(fromUnit) === getUnitCategory(toUnit);
}

export function convertQuantity(quantity: number, fromUnit: ProductUnit, toUnit: ProductUnit): number {
    if (!canConvertUnits(fromUnit, toUnit)) return quantity;

    const normalizedQuantity = normalizeUnitValue(quantity);
    const baseValue = normalizedQuantity * getBaseFactor(fromUnit);
    return baseValue / getBaseFactor(toUnit);
}

export function normalizeProductUnit(unit: string | null | undefined): ProductUnit {
    if (!unit) return DEFAULT_PRODUCT_UNIT;
    return PRODUCT_UNITS.includes(unit as ProductUnit) ? (unit as ProductUnit) : DEFAULT_PRODUCT_UNIT;
}

export const normalizeSellingUnit = normalizeProductUnit;

export function normalizeStockUnit(unit: string | null | undefined): ProductUnit {
    if (!unit) return DEFAULT_STOCK_UNIT;
    return PRODUCT_UNITS.includes(unit as ProductUnit) ? (unit as ProductUnit) : DEFAULT_STOCK_UNIT;
}

export function getUnitLabel(unit: string | null | undefined): string {
    const normalized = normalizeProductUnit(unit);
    return UNIT_LABELS[normalized];
}

export function normalizeUnitValue(value: number | string | null | undefined): number {
    const parsed = typeof value === 'number' ? value : Number(value);
    if (!Number.isFinite(parsed) || parsed <= 0) return DEFAULT_UNIT_VALUE;
    return parsed;
}

export function formatUnitValue(value: number | string | null | undefined): string {
    const normalized = normalizeUnitValue(value);
    if (Number.isInteger(normalized)) return normalized.toString();
    return normalized.toString();
}

export function formatQuantityLabel(
    quantity: number | string | null | undefined,
    unit: string | null | undefined
): string {
    const normalizedQuantity = normalizeUnitValue(quantity);
    const normalizedUnit = normalizeProductUnit(unit);

    if (normalizedUnit === 'item') {
        const suffix = normalizedQuantity === 1 ? 'item' : 'items';
        return `${formatUnitValue(normalizedQuantity)} ${suffix}`;
    }

    return `${formatUnitValue(normalizedQuantity)}${getUnitLabel(normalizedUnit)}`;
}

export function formatPriceWithUnit(
    price: number,
    sellingUnit: string | null | undefined,
    sellingUnitValue: number | string | null | undefined
): string {
    return `Rs. ${Number(price).toLocaleString(undefined, { minimumFractionDigits: 2 })}`;
}

export function formatStockWithUnit(stockQuantity: number, stockUnit: string | null | undefined): string {
    return `${Number(stockQuantity).toLocaleString()}${getUnitLabel(stockUnit)}`;
}

export const variantSchema = z.object({
    id: z.string().optional(),
    sku: z.string().optional().nullable().or(z.literal('')),
    options: z.record(z.string(), z.string()),
    price_override: z.coerce.number().optional().nullable(),
    compare_at_price: z.coerce.number().optional().nullable(),
    stock_quantity: z.coerce.number().min(0).default(0),
    image_url: z.string().url().optional().nullable().or(z.literal('')),
});

export const productUpsertSchema = z.object({
    title: z.string().trim().min(1, 'Product title is required.'),
    description: z.string().optional().default(''),
    price: z.coerce.number().gt(0, 'Price must be greater than 0.'),
    compare_at_price: z.coerce.number().optional().nullable(),
    selling_unit_value: z.coerce.number().gt(0, 'Selling unit value must be greater than 0.'),
    selling_unit: z.enum(PRODUCT_UNITS, { error: 'Selling unit is required.' }),
    stock_quantity: z.coerce.number().min(0, 'Stock quantity cannot be negative.'),
    stock_unit: z.enum(PRODUCT_UNITS, { error: 'Stock unit is required.' }),
    low_stock_threshold: z.coerce.number().min(0, 'Low stock threshold cannot be negative.'),
    image_urls: z.array(z.string().url()).default([]),
    has_variants: z.boolean().default(false),
    variation_options: z.array(z.object({
        name: z.string(),
        values: z.array(z.string())
    })).default([]),
    variants: z.array(variantSchema).default([]),
});

export type ProductUpsertInput = z.infer<typeof productUpsertSchema>;
